"use client";

import {
  Fragment,
  useEffect,
  useId,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from "react";
import { FormProvider, useFormState, useWatch } from "react-hook-form";
import { cn } from "@/lib/utils";
import { Separator } from "@/components/ui/separator";

import { useJsonForm } from "./hooks/use-json-form";
import { useDebouncedCallback } from "./hooks/use-debounced-callback";
import { mergeStrings } from "./lib/strings";
import { defaultJsonFormRegistry } from "./lib/default-registry";
import { flattenRhfErrorsToRecord } from "./lib/flatten-errors";
import { isValueField } from "./lib/validate-schema";
import { JsonFormProvider, useJsonFormContext } from "./json-form-context";
import { FieldWrapper } from "./parts/field-wrapper";
import { FieldFallback } from "./parts/field-fallback";
import { FormHeader } from "./parts/form-header";
import { JsonFormErrorSummary } from "./parts/error-summary";
import { JsonFormSubmitButton } from "./parts/submit-button";
import { JsonFormResetButton } from "./parts/reset-button";
import type {
  FieldDefinition,
  FieldRenderer,
  JsonFormContextValue,
  JsonFormProps,
} from "./types";

/**
 * Top-level component. Composes our `<JsonFormProvider>` + RHF's
 * `<FormProvider>` + a layout shell that walks `schema.fields` and renders
 * each via the resolver chain (`renderField` → `fieldRegistry` → default).
 */
export function JsonForm<
  TValues extends Record<string, unknown> = Record<string, unknown>,
>({
  schema,
  defaultValues,
  values,
  onSubmit,
  onSubmitError,
  onSubmitAttempt,
  onChange,
  onChangeDebounce = 100,
  onValidationChange,
  onReady,
  columns = 1,
  labelPosition = "top",
  showSummary,
  summaryStrategy = "post-submit",
  showSchemaHeader = true,
  submitButton,
  resetButton,
  fieldRegistry,
  renderField,
  validationMode = "onTouched",
  strings: stringsOverride,
  className,
  style,
  ref,
}: JsonFormProps<TValues>) {
  const formId = useId();
  const strings = useMemo(() => mergeStrings(stringsOverride), [stringsOverride]);
  const [hasSubmitted, setHasSubmitted] = useState(false);

  const { form, zodSchema, handle } = useJsonForm<TValues>(schema, {
    defaultValues,
    values,
    validationMode,
    strings: stringsOverride,
  });

  // Merge consumer registry with the default.
  const mergedRegistry = useMemo<Record<string, FieldRenderer>>(
    () => ({ ...defaultJsonFormRegistry, ...(fieldRegistry ?? {}) }),
    [fieldRegistry],
  );

  // `hasSubmitted` deliberately lives on a sibling context (provided to
  // `<JsonFormProvider>` as a prop) — keeping it OUT of this memo means the
  // first-submit flip doesn't invalidate the main context and re-render every
  // field. The compat field on the value (set to `false` here) is overwritten
  // by `useJsonFormContext` reads, which merge in the narrow context.
  const ctx = useMemo<JsonFormContextValue<TValues>>(
    () => ({
      ...handle,
      rhf: form,
      schema,
      zodSchema,
      strings,
      formId,
      hasSubmitted: false,
      fieldRegistry: mergedRegistry,
    }),
    [handle, form, schema, zodSchema, strings, formId, mergedRegistry],
  );

  useImperativeHandle(ref, () => handle, [handle]);

  // T3.7 — fire `onReady` once after mount + defaults applied. Stored in a
  // ref so a parent re-render that passes a fresh callback identity doesn't
  // re-fire (the contract is "once per form lifetime"). Ref-write happens
  // inside an effect (React Compiler bans mutation during render).
  const onReadyRef = useRef(onReady);
  useEffect(() => {
    onReadyRef.current = onReady;
  }, [onReady]);
  const readyFiredRef = useRef(false);
  useEffect(() => {
    if (readyFiredRef.current) return;
    readyFiredRef.current = true;
    onReadyRef.current?.({ formApi: handle });
  }, [handle]);

  // Debounced onChange that subscribes to the values bag.
  const debouncedChange = useDebouncedCallback((vals: Record<string, unknown>) => {
    onChange?.({ values: vals as TValues, formApi: handle });
  }, onChangeDebounce);

  return (
    <FormProvider {...form}>
      <JsonFormProvider value={ctx as JsonFormContextValue} hasSubmitted={hasSubmitted}>
        <form
          noValidate
          className={cn("flex flex-col gap-4", className)}
          style={style}
          onSubmit={(e) => {
            e.preventDefault();
            setHasSubmitted(true);
            // T3.6 — fires unconditionally before validation runs.
            onSubmitAttempt?.({ formApi: handle });
            void form.handleSubmit(
              async (vals) => {
                await onSubmit({
                  values: vals as TValues,
                  formApi: handle,
                });
              },
              (errs) => {
                const flat = flattenRhfErrorsToRecord(errs);
                onSubmitError?.({
                  errors: flat,
                  formApi: handle,
                });
                onValidationChange?.({
                  isValid: false,
                  errors: flat,
                });
                // T2.2 — focus the first focusable invalid field in DOM
                // order (schema.fields order). Skip non-focusable types
                // (`computed` is `<output>`, `hidden`/`section`/`divider`
                // render no control); falling through to the next errored
                // field beats a silent no-op `setFocus` call.
                const focusTarget = schema.fields.find(
                  (f) =>
                    isValueField(f) &&
                    f.type !== "computed" &&
                    f.type !== "hidden" &&
                    flat[f.name] !== undefined,
                );
                if (focusTarget) {
                  try {
                    form.setFocus(focusTarget.name as never);
                  } catch {
                    // Fall through — non-registered name (rare; safer to
                    // skip than to throw out of a submit handler).
                  }
                }
              },
            )(e);
          }}
        >
          <ChangeBridge
            onChange={onChange ? debouncedChange : undefined}
            onValidationChange={onValidationChange}
          />

          {showSchemaHeader ? <FormHeader /> : null}

          {showSummary ? (
            <JsonFormErrorSummary strategy={summaryStrategy} />
          ) : null}

          <FieldList
            fields={schema.fields}
            registry={mergedRegistry}
            renderField={renderField}
            columns={columns}
            labelPosition={labelPosition}
          />

          {(submitButton !== false || resetButton) ? (
            <SubmitRow
              submitButton={submitButton}
              resetButton={resetButton}
            />
          ) : null}
        </form>
      </JsonFormProvider>
    </FormProvider>
  );
}

// ─── Change + validation bridge ──────────────────────────────────────────────

function ChangeBridge({
  onChange,
  onValidationChange,
}: {
  onChange?: (vals: Record<string, unknown>) => void;
  onValidationChange?: (args: {
    isValid: boolean;
    errors: Record<string, string>;
  }) => void;
}) {
  const values = useWatch();
  const { isValid, errors } = useFormState();
  const rendered = useRef(0);
  const lastValuesKey = useRef<string | null>(null);
  const lastValidity = useRef<{ isValid: boolean; errorKey: string } | null>(null);

  useEffect(() => {
    // Skip first synthetic emit (initial mount) so we don't fire onChange
    // before the user has touched anything.
    if (rendered.current === 0) {
      rendered.current++;
      lastValuesKey.current = stableStringify(values);
      return;
    }
    // Structural-equality guard breaks the controlled-mode echo loop: when
    // a consumer pipes `onChange` back through the `values` prop, RHF
    // re-runs `useWatch` and produces a new reference for the same payload.
    // Without this guard the debounced fire-out would still leak, defeating
    // defense #2 of the controlled-mode three-defenses pattern.
    const next = stableStringify(values);
    if (next === lastValuesKey.current) return;
    lastValuesKey.current = next;
    onChange?.((values ?? {}) as Record<string, unknown>);
  }, [values, onChange]);

  useEffect(() => {
    if (!onValidationChange) return;
    const flat = flattenRhfErrorsToRecord(errors as Record<string, unknown>);
    const errorKey = `${Object.keys(flat).length}:${Object.keys(flat).join(",")}`;
    const last = lastValidity.current;
    if (last && last.isValid === isValid && last.errorKey === errorKey) return;
    lastValidity.current = { isValid, errorKey };
    onValidationChange({ isValid, errors: flat });
  }, [isValid, errors, onValidationChange]);

  return null;
}

// ─── Field-list layout (sections / dividers / rows) ──────────────────────────

interface FieldListProps {
  fields: ReadonlyArray<FieldDefinition>;
  registry: Record<string, FieldRenderer>;
  renderField?: (args: {
    field: FieldDefinition;
    defaultRender: () => ReactNode;
  }) => ReactNode;
  columns: 1 | 2;
  labelPosition: "top" | "left";
}

function FieldList({
  fields,
  registry,
  renderField,
  columns,
  labelPosition,
}: FieldListProps) {
  const gridClass =
    columns === 2 ? "grid grid-cols-1 gap-4 md:grid-cols-2" : "flex flex-col gap-4";

  // Walk fields linearly. Section/divider are inline siblings — they break the
  // grid rhythm (full-width) but don't introduce nested DOM groups, keeping
  // the layout simple for v0.1.0.
  return (
    <div className={gridClass}>
      {fields.map((field) => {
        if (field.type === "section") {
          return (
            <section
              key={field.name}
              data-jsonform-section={field.name}
              className={cn("col-span-full mt-2 flex flex-col gap-1", columns === 2 && "md:col-span-2")}
            >
              {field.label ? (
                <h3 className="text-sm font-semibold uppercase tracking-wide text-muted-foreground">
                  {field.label}
                </h3>
              ) : null}
              {field.description ? (
                <p className="text-xs text-muted-foreground">
                  {field.description}
                </p>
              ) : null}
            </section>
          );
        }

        if (field.type === "divider") {
          return (
            <div
              key={field.name}
              data-jsonform-divider={field.name}
              className={cn("col-span-full", columns === 2 && "md:col-span-2")}
            >
              <Separator />
            </div>
          );
        }

        const renderer = registry[field.type] ?? registry["__fallback__"] ?? FieldFallback;
        const defaultRender = () => (
          <FieldWrapper
            field={field}
            renderer={renderer}
            formLabelPosition={labelPosition}
          />
        );

        return (
          <Fragment key={field.name}>
            {renderField
              ? renderField({ field, defaultRender })
              : defaultRender()}
          </Fragment>
        );
      })}
    </div>
  );
}

// ─── Submit row ──────────────────────────────────────────────────────────────

function SubmitRow({
  submitButton,
  resetButton,
}: {
  submitButton: JsonFormProps["submitButton"];
  resetButton: JsonFormProps["resetButton"];
}) {
  if (typeof submitButton === "function") {
    return (
      <SubmitFunctionRow render={submitButton} resetButton={resetButton} />
    );
  }

  const cfg = submitButton ?? {};
  const align = (cfg && typeof cfg === "object" ? cfg.align : "right") ?? "right";
  const alignClass =
    align === "left"
      ? "justify-start"
      : align === "center"
        ? "justify-center"
        : "justify-end";

  return (
    <div className={cn("flex items-center gap-2 pt-1", alignClass)}>
      {resetButton ? (
        <JsonFormResetButton
          label={resetButton.label}
          variant={resetButton.variant}
        />
      ) : null}
      {submitButton !== false ? (
        <JsonFormSubmitButton
          label={cfg && typeof cfg === "object" ? cfg.label : undefined}
          variant={cfg && typeof cfg === "object" ? cfg.variant : undefined}
          disableWhenInvalid={
            cfg && typeof cfg === "object"
              ? cfg.disableWhenInvalid
              : undefined
          }
        />
      ) : null}
    </div>
  );
}

function SubmitFunctionRow({
  render,
  resetButton,
}: {
  render: Extract<
    JsonFormProps["submitButton"],
    (args: { isSubmitting: boolean; isValid: boolean }) => ReactNode
  >;
  resetButton: JsonFormProps["resetButton"];
}) {
  // Read isSubmitting / isValid via context-aware atoms.
  return (
    <div className="flex items-center justify-end gap-2 pt-1">
      {resetButton ? (
        <JsonFormResetButton
          label={resetButton.label}
          variant={resetButton.variant}
        />
      ) : null}
      <SubmitRenderProxy render={render} />
    </div>
  );
}

function SubmitRenderProxy({
  render,
}: {
  render: (args: { isSubmitting: boolean; isValid: boolean }) => ReactNode;
}) {
  const ctx = useJsonFormContext();
  return (
    <>
      {render({
        isSubmitting: ctx.rhf.formState.isSubmitting,
        isValid: ctx.rhf.formState.isValid,
      })}
    </>
  );
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

/**
 * Key-sorted JSON stringify so `{ a: 1, b: 2 }` and `{ b: 2, a: 1 }` hash to
 * the same key. Used by `ChangeBridge` to detect echo-loop re-emissions of a
 * structurally-identical values bag.
 */
function stableStringify(input: unknown): string {
  if (input === null || typeof input !== "object") return JSON.stringify(input);
  if (Array.isArray(input)) return `[${input.map(stableStringify).join(",")}]`;
  const keys = Object.keys(input as Record<string, unknown>).sort();
  return `{${keys
    .map((k) => `${JSON.stringify(k)}:${stableStringify((input as Record<string, unknown>)[k])}`)
    .join(",")}}`;
}

"use client";

import { createContext, useContext, type ReactNode } from "react";
import type { JsonFormContextValue } from "./types";

/* eslint-disable @typescript-eslint/no-explicit-any -- `Record<string, any>` is required to satisfy react-hook-form's `FieldValues` constraint; `unknown` won't type-check there. */

const JsonFormContext = createContext<JsonFormContextValue | null>(null);

/**
 * Narrow context that ONLY carries `hasSubmitted`. Split from the main
 * `JsonFormContext` (v0.1.3) so that flipping `hasSubmitted` false→true on
 * the first submit doesn't invalidate the memoized main context — which
 * would re-render every field that consumes it. Only `<JsonFormErrorSummary>`
 * actually needs to react to this flag.
 */
const JsonFormSubmittedContext = createContext<boolean>(false);

export interface JsonFormProviderProps<TValues extends Record<string, any> = Record<string, any>> {
  value: JsonFormContextValue<TValues>;
  /**
   * Has the form attempted a submit at least once? Drives the
   * `post-submit` error-summary strategy. Optional — defaults to `false`.
   * Provided as a sibling prop (not on `value`) so updating it doesn't
   * invalidate the memoized main context.
   */
  hasSubmitted?: boolean;
  children: ReactNode;
}

export function JsonFormProvider<TValues extends Record<string, any> = Record<string, any>>({
  value,
  hasSubmitted = false,
  children,
}: JsonFormProviderProps<TValues>) {
  return (
    <JsonFormContext.Provider value={value as JsonFormContextValue}>
      <JsonFormSubmittedContext.Provider value={hasSubmitted}>
        {children}
      </JsonFormSubmittedContext.Provider>
    </JsonFormContext.Provider>
  );
}

/**
 * Accessor hook for the JsonForm context. Use inside standalone parts
 * (`<JsonFormField>`, `<JsonFormErrorSummary>`, etc.) or to build a fully
 * headless layout while still using our context.
 *
 * v0.1.3 — the returned context's `hasSubmitted` is a read-time snapshot
 * from the narrow `JsonFormSubmittedContext` so consumers that depend on it
 * re-render only when it flips. Most consumers should not need this; reach
 * for `useJsonFormHasSubmitted()` if you only need the flag.
 */
export function useJsonFormContext<TValues extends Record<string, any> = Record<string, any>>(): JsonFormContextValue<TValues> {
  const ctx = useContext(JsonFormContext);
  const hasSubmitted = useContext(JsonFormSubmittedContext);
  if (!ctx) {
    throw new Error(
      "[json-form] useJsonFormContext must be used inside a <JsonForm> or <JsonFormProvider>.",
    );
  }
  // Reattach `hasSubmitted` so callers reading `ctx.hasSubmitted` still work,
  // even though it lives on a separate context internally.
  return { ...ctx, hasSubmitted } as JsonFormContextValue<TValues>;
}

/**
 * Narrow accessor — returns just the `hasSubmitted` flag. Use this in
 * standalone parts that ONLY care about post-submit state (e.g.,
 * `<JsonFormErrorSummary>`) so they don't re-render on every main-context
 * change.
 */
export function useJsonFormHasSubmitted(): boolean {
  return useContext(JsonFormSubmittedContext);
}

/**
 * v0.2.1 — non-throwing variant of `useJsonFormContext`. Returns `null`
 * when no `<JsonFormProvider>` is in the tree. Internal-only — exported
 * for `<JsonFormDevtools>` to render a soft-warning fallback panel
 * instead of throwing when consumers forget the Provider wrap.
 */
export function useJsonFormContextOptional<TValues extends Record<string, any> = Record<string, any>>(): JsonFormContextValue<TValues> | null {
  const ctx = useContext(JsonFormContext);
  const hasSubmitted = useContext(JsonFormSubmittedContext);
  if (!ctx) return null;
  return { ...ctx, hasSubmitted } as JsonFormContextValue<TValues>;
}

/* eslint-enable @typescript-eslint/no-explicit-any */

// Top-level component + standalone parts
export { JsonForm } from "./json-form";
export {
  JsonFormProvider,
  useJsonFormContext,
  useJsonFormHasSubmitted,
} from "./json-form-context";
export { JsonFormField } from "./parts/json-form-field";
export { JsonFormErrorSummary } from "./parts/error-summary";
export { JsonFormSubmitButton } from "./parts/submit-button";
export { JsonFormResetButton } from "./parts/reset-button";
export { FormHeader as JsonFormHeader } from "./parts/form-header";
export { FieldWrapper as JsonFormFieldWrapper } from "./parts/field-wrapper";
export {
  JsonFormDevtools,
  type JsonFormDevtoolsProps,
} from "./parts/json-form-devtools";

// Headless factory + default registry (consumer can spread + extend)
export { useJsonForm } from "./hooks/use-json-form";
export {
  useJsonFormFieldValue,
  useJsonFormFieldsValue,
} from "./hooks/use-json-form-field-value";
export { defaultJsonFormRegistry } from "./lib/default-registry";
export { defineFieldRenderer } from "./lib/define-field-renderer";

// String dictionary + helpers
export { defaultStrings as defaultJsonFormStrings, mergeStrings as mergeJsonFormStrings } from "./lib/strings";

// Note: `ARTICLE_BODY_EMPTY_VALUE` (the canonical Plate "empty paragraph"
// default) is intentionally NOT re-exported from this barrel. Earlier
// attempts (v0.1.3 + v0.1.4) hit a shadcn path-rewriter inconsistency
// where cross-slug imports from `index.ts` (and `lib/*.ts`) didn't get
// the same flattening as imports from `parts/*.tsx`. Consumers using
// `richtext` fields should import the empty default directly from
// `@ilinxa/article-body-01`:
//
//   import { ARTICLE_BODY_EMPTY_VALUE } from "@/components/article-body-01";
//
// (or whatever the consumer-side path is for their setup). Documented
// in usage.tsx.

// Public types
export type {
  ButtonVariant,
  Condition,
  ConditionOrFn,
  FieldConfig,
  FieldAriaProps,
  FieldDefinition,
  FieldOption,
  FieldOptionsResolver,
  FieldRenderer,
  FieldRendererArgs,
  FieldType,
  FieldValidators,
  FormSchema,
  JsonFormContextValue,
  JsonFormHandle,
  JsonFormProps,
  JsonFormStrings,
  JsonFormSubmitErrorArgs,
  JsonFormValidationChangeArgs,
  JsonFormValuesArgs,
  UseJsonFormOptions,
  UseJsonFormReturn,
} from "./types";

import type { CSSProperties, ReactNode, Ref } from "react";
import type { UseFormReturn } from "react-hook-form";
import type { ZodObject, ZodTypeAny } from "zod";

/* eslint-disable @typescript-eslint/no-explicit-any -- `Record<string, any>` is required to satisfy react-hook-form's `FieldValues` constraint; `unknown` won't type-check there. */

// ─── Field DSL ───────────────────────────────────────────────────────────────

/** All built-in v0.1.x field types, plus string for consumer-registered ones. */
export type FieldType =
  // text family
  | "text" | "email" | "password" | "url" | "tel" | "textarea" | "number"
  // choice family
  | "select" | "multi-select" | "radio-group" | "checkbox" | "checkbox-group" | "switch"
  // date/time family
  | "date" | "date-range" | "time" | "datetime"
  // rich / composite (v0.1.0 + v0.1.1 `richtext`)
  | "code" | "slider" | "rating" | "richtext"
  // special
  | "computed" | "hidden" | "section" | "divider"
  // consumer-extended (registry lookup); also covers v0.1.x types ('file', 'color', 'array') before they ship
  | (string & {});

/** Static-array form of options. */
export interface FieldOption {
  value: unknown;
  label: string;
  description?: string;
  disabled?: boolean;
}

/** Async resolver form of options. */
export type FieldOptionsResolver = (args: {
  query?: string;
  allValues: Record<string, unknown>;
  /**
   * v0.1.6 — abort signal. Fires when the resolver run is superseded by a
   * newer query/dep change or the field unmounts. Fetch-based resolvers
   * should pass this to `fetch(url, { signal })`; ignoring it is harmless
   * (the result is still discarded by the generation guard).
   */
  signal: AbortSignal;
}) => Promise<FieldOption[]>;

/** Per-field type-specific config (hybrid shape — A1 resolution). */
export interface FieldConfig {
  code?: { editorExtensions?: unknown[]; readOnly?: boolean };
  date?: { firstDayOfWeek?: 0 | 1 | 2 | 3 | 4 | 5 | 6; minYear?: number; maxYear?: number };
  rating?: { stars?: number };
  /** v0.1.1 — Plate-based richtext field config. `hideToolbar` collapses both top and floating toolbars. */
  richText?: { hideToolbar?: boolean; autoFocus?: boolean };
  // v0.1.x additions land here non-breakingly: file?, color?
}

/** Declarative validators block. Compiled to Zod chain at schema-compile time. */
export interface FieldValidators {
  required?: boolean | string;
  min?: number | string | { value: number | string; message: string };
  max?: number | string | { value: number | string; message: string };
  minLength?: number | { value: number; message: string };
  maxLength?: number | { value: number; message: string };
  pattern?: string | { value: string; message: string };
  email?: boolean | { message: string };
  url?: boolean | { message: string };
}

/** Condition DSL — 11 operators + function escape hatch. */
export type Condition =
  | { field: string; equals: unknown }
  | { field: string; notEquals: unknown }
  | { field: string; in: ReadonlyArray<unknown> }
  | { field: string; notIn: ReadonlyArray<unknown> }
  | { field: string; matches: string }
  | { field: string; truthy: boolean }
  | { field: string; greaterThan: number }
  | { field: string; lessThan: number }
  | { all: ReadonlyArray<Condition> }
  | { any: ReadonlyArray<Condition> }
  | { not: Condition };

export type ConditionOrFn =
  | Condition
  | ((args: { values: Record<string, unknown> }) => boolean);

/**
 * A single field definition in the JSON schema.
 *
 * `name` is REQUIRED for all field types — including `section` and `divider`,
 * which produce no value but use `name` as a stable React key. Consumer
 * convention: prefix non-value-carrying names with `_` (e.g., `'_personal'`,
 * `'_divider1'`). Compiler ignores `name` for `section`/`divider` when
 * building the ZodObject.
 */
export interface FieldDefinition {
  name: string;
  type: FieldType;
  label?: string;
  description?: string;
  placeholder?: string;
  defaultValue?: unknown;

  validators?: FieldValidators;
  validate?: (args: { value: unknown; allValues: Record<string, unknown> }) => string | undefined;
  validateAsync?: (args: { value: unknown; allValues: Record<string, unknown> }) => Promise<string | undefined>;
  validateAsyncDebounce?: number;

  visibleWhen?: ConditionOrFn;
  enabledWhen?: ConditionOrFn;
  requiredWhen?: ConditionOrFn;
  keepValueWhenHidden?: boolean;

  options?: ReadonlyArray<FieldOption> | FieldOptionsResolver;
  searchable?: boolean;
  optionsDebounce?: number;
  min?: number; max?: number; step?: number;
  rows?: number;
  lang?: string;

  config?: FieldConfig;

  expression?: string;
  compute?: (args: { values: Record<string, unknown> }) => unknown;
  editable?: boolean;

  row?: string;
  colSpan?: "full" | 1 | 2;
  width?: "full" | "half" | "third" | "quarter" | number;
  labelPosition?: "top" | "left";

  disabled?: boolean;
  readOnly?: boolean;
  autoComplete?: string;
  autoFocus?: boolean;

  /**
   * v0.1.6 — typed metadata for downstream per-locale renderers (T3.8).
   * Upstream `JsonForm` itself does NOT change behavior based on this flag;
   * the contract is purely "this field's value is locale-aware." A
   * consumer-side HOC composed into the registry (e.g., `withPerLocale`)
   * reads this flag and renders a locale-tab strip around the underlying
   * renderer. See the docs for the canonical HOC pattern.
   */
  translatable?: boolean;

  /**
   * Declares which field paths this renderer's `allValues` access depends
   * on. The FieldWrapper resolves a per-field subscription mode against
   * this flag (active as of v0.2.0):
   *
   * - `undefined` (default) → full-bag subscription; preserves v0.1.x
   *   behavior for unmigrated custom renderers.
   * - `[]` → no subscription; renderer receives a `getValues()` snapshot
   *   under `allValues`. Use this when the renderer doesn't read
   *   `allValues` at all (the most common case for custom renderers).
   * - `['a', 'b']` → narrow subscription; `allValues` is rebuilt from the
   *   watched paths only via `setByPath`.
   *
   * Built-in default-registry renderers (`text`, `radio-group`, `checkbox`,
   * etc.) auto-skip the subscription per an internal whitelist — declare
   * `dependsOn` only on custom renderers, or to override the whitelist for
   * a specific field. The whitelist check resolves on the FINAL renderer
   * identity (not on `field.type` alone), so a consumer-registered renderer
   * replacing `text` correctly opts back into full-bag unless it sets
   * `dependsOn`.
   *
   * **Stable identity:** the array reference should be stable across renders
   * (module-scope const or `useMemo`-cached). RHF de-dupes subscription
   * targets by content, so an unstable reference doesn't break correctness,
   * but stable refs avoid wasted reconciles.
   *
   * `validateSchemaDev` warns when `dependsOn` references a field name that
   * doesn't exist in `schema.fields[].name`.
   */
  dependsOn?: ReadonlyArray<string>;
}

/** Top-level form schema. */
export interface FormSchema {
  fields: ReadonlyArray<FieldDefinition>;
  validate?: (args: { values: Record<string, unknown> }) => Record<string, string> | undefined;
  zodSchema?: ZodObject<Record<string, ZodTypeAny>>;
  meta?: { id?: string; version?: string; title?: string; description?: string };
}

// ─── Callback arg shapes (object-shape per F-cross-12) ───────────────────────

export interface JsonFormValuesArgs<TValues> {
  values: TValues;
  formApi: JsonFormHandle<TValues>;
}

export interface JsonFormSubmitErrorArgs<TValues> {
  errors: Record<string, string>;
  formApi: JsonFormHandle<TValues>;
}

export interface JsonFormValidationChangeArgs {
  isValid: boolean;
  errors: Record<string, string>;
}

// ─── FieldRenderer (T1 lock — single canonical name) ─────────────────────────

/**
 * ARIA attributes the field-wrapper computes once per render and passes to
 * the renderer. Renderers MUST attach these to the appropriate interactive
 * element:
 *
 * - **Native form controls** (`<input>`, `<textarea>`, `<button>`, etc.):
 *   spread `id` + `aria-required` + `aria-invalid` + `aria-disabled` +
 *   `aria-describedby` onto the element. The wrapper's `<label htmlFor>`
 *   targets the same `id`.
 * - **Group-style controls** (`role="radiogroup"`, `role="group"`,
 *   custom widgets): attach `aria-labelledby={labelledBy}` to the group root
 *   instead of `id` (HTML `label[for]` doesn't bind to non-form controls).
 *   Still spread the remaining `aria-*` attributes.
 *
 * v0.1.2 — `ariaProps` replaces the v0.1.0 `Slot.Root` forwarding strategy.
 * That approach silently failed for Popover-wrapped controls and ARIA groups
 * because Radix `Popover.Root` is a context-only component (no DOM node).
 */
export interface FieldAriaProps {
  /** Use on native form controls so `label[htmlFor]` binds correctly. */
  id: string;
  /** Use on group-style controls via `aria-labelledby`. */
  labelledBy: string;
  "aria-required"?: true;
  "aria-invalid"?: true;
  "aria-disabled"?: true;
  "aria-describedby"?: string;
}

export interface FieldRendererArgs {
  field: FieldDefinition;
  value: unknown;
  onChange: (next: unknown) => void;
  onBlur: () => void;
  error: string | undefined;
  disabled: boolean;
  readOnly: boolean;
  /**
   * The form's current values bag. **Freshness depends on the field's
   * subscription mode** (resolved per-field as of v0.2.0):
   *
   * - **Snapshot mode** (built-in default renderers OR `dependsOn: []`):
   *   captured via `getValues()` at render time. Stays fresh on the field's
   *   own value changes (Controller re-renders), but DOES NOT reflect
   *   changes to other fields between renders. If a custom renderer in
   *   snapshot mode needs live values, subscribe via
   *   `useJsonFormFieldValue` / `useJsonFormFieldsValue` instead of reading
   *   from `allValues`.
   * - **Narrow mode** (`dependsOn: ['a','b']`): live for the declared paths;
   *   `setByPath`-rebuilt so dot-paths read correctly.
   * - **Full-bag mode** (`dependsOn` omitted on a custom renderer): live
   *   across the whole form. Preserves v0.1.x behavior.
   */
  allValues: Record<string, unknown>;
  formApi: JsonFormHandle<Record<string, unknown>>;
  /** v0.1.2 — ARIA bridge. See `FieldAriaProps` for usage rules. */
  ariaProps: FieldAriaProps;
}

export type FieldRenderer = (args: FieldRendererArgs) => ReactNode;

// ─── Imperative handle ────────────────────────────────────────────────────────

export interface JsonFormHandle<TValues = Record<string, unknown>> {
  submit: () => Promise<{ ok: boolean; values?: TValues; errors?: Record<string, string> }>;
  reset: (values?: Partial<TValues>) => void;
  setValue: (name: string, value: unknown) => void;
  getValue: (name: string) => unknown;
  getValues: () => TValues;
  setError: (name: string, message: string) => void;
  clearErrors: (name?: string) => void;
  trigger: (name?: string | string[]) => Promise<boolean>;
  focus: (name: string) => void;
  isDirty: () => boolean;
  isValid: () => boolean;
  isSubmitting: () => boolean;
}

// ─── Strings dictionary ───────────────────────────────────────────────────────

export interface JsonFormStrings {
  submit: string;
  reset: string;
  requiredIndicator: string;
  optionalIndicator: string;
  loadingOptions: string;
  optionsError: string;
  optionsRetry: string;
  noOptions: string;
  summaryHeading: string;
  submitFailed: string;
  errorTemplates: {
    required: string;
    minLength: string;
    maxLength: string;
    min: string;
    max: string;
    pattern: string;
    email: string;
    url: string;
  };
}

// ─── Component props ──────────────────────────────────────────────────────────

export type ButtonVariant = "default" | "outline" | "ghost" | "secondary" | "destructive";

export interface JsonFormProps<TValues extends Record<string, any> = Record<string, unknown>> {
  schema: FormSchema;
  defaultValues?: Partial<TValues>;
  values?: Partial<TValues>;

  onSubmit: (args: JsonFormValuesArgs<TValues>) => void | Promise<void>;
  onSubmitError?: (args: JsonFormSubmitErrorArgs<TValues>) => void;
  /**
   * v0.1.6 (T3.6) — fires on every submit press, BEFORE validation runs.
   * Use for "user attempted submit" telemetry / submit-counter UX hints
   * that need to fire even when validation rejects the attempt. `onSubmit`
   * still gates on validation passing.
   */
  onSubmitAttempt?: (args: { formApi: JsonFormHandle<TValues> }) => void;
  onChange?: (args: JsonFormValuesArgs<TValues>) => void;
  onChangeDebounce?: number;
  onValidationChange?: (args: JsonFormValidationChangeArgs) => void;
  /**
   * v0.1.6 (T3.7) — fires once after mount + defaults applied. Async-schema
   * consumers (load schema → mount → wire callbacks) can ditch the manual
   * `useEffect(...)` they wrote to capture the imperative handle.
   */
  onReady?: (args: { formApi: JsonFormHandle<TValues> }) => void;

  columns?: 1 | 2;
  labelPosition?: "top" | "left";
  showSummary?: boolean;
  summaryStrategy?: "always" | "post-submit";
  showSchemaHeader?: boolean;

  submitButton?:
    | {
        label?: string;
        variant?: ButtonVariant;
        align?: "left" | "right" | "center";
        disableWhenInvalid?: boolean;
      }
    | ((args: { isSubmitting: boolean; isValid: boolean }) => ReactNode)
    | false;
  resetButton?: { label?: string; variant?: ButtonVariant };

  fieldRegistry?: Record<string, FieldRenderer>;
  renderField?: (args: { field: FieldDefinition; defaultRender: () => ReactNode }) => ReactNode;

  validationMode?: "onChange" | "onBlur" | "onTouched" | "onSubmit" | "all";

  strings?: Partial<JsonFormStrings>;
  className?: string;
  style?: CSSProperties;
  ref?: Ref<JsonFormHandle<TValues>>;
}

// ─── Standalone-parts contexts ────────────────────────────────────────────────

export type JsonFormContextValue<TValues extends Record<string, any> = Record<string, any>> = JsonFormHandle<TValues> & {
  /**
   * Escape hatch — the raw react-hook-form return. Standalone parts read
   * `formState`, register custom controllers, etc. through this. NOT part of
   * the json-form stability contract: if RHF renames or relocates API
   * surface, this type follows. Prefer the typed handle methods
   * (`setValue` / `getValue` / `trigger` / …) for anything reachable that
   * way.
   */
  rhf: UseFormReturn<TValues>;
  schema: FormSchema;
  zodSchema: ZodObject<Record<string, ZodTypeAny>>;
  strings: JsonFormStrings;
  formId: string;
  hasSubmitted: boolean;
  /** Merged field registry (default ⨯ consumer overrides). Exposed for standalone parts that resolve renderers. */
  fieldRegistry: Record<string, FieldRenderer>;
};

export interface UseJsonFormReturn<TValues extends Record<string, any>> {
  form: UseFormReturn<TValues>;
  zodSchema: ZodObject<Record<string, ZodTypeAny>>;
  fieldList: ReadonlyArray<FieldDefinition>;
  isValid: boolean;
  isSubmitting: boolean;
  handle: JsonFormHandle<TValues>;
}

export interface UseJsonFormOptions<TValues extends Record<string, any>> {
  defaultValues?: Partial<TValues>;
  values?: Partial<TValues>;
  validationMode?: "onChange" | "onBlur" | "onTouched" | "onSubmit" | "all";
  strings?: Partial<JsonFormStrings>;
}

/* eslint-enable @typescript-eslint/no-explicit-any */

"use client";

import { Suspense, useEffect, useRef, type ReactNode } from "react";
import { Controller, useFormContext, useWatch } from "react-hook-form";
import type { FieldValues, Path } from "react-hook-form";
import { cn } from "@/lib/utils";
import type { FieldAriaProps, FieldDefinition, FieldRenderer } from "../types";
import { useConditional } from "../hooks/use-conditional";
import { useJsonFormContext } from "../json-form-context";
import {
  BUILTIN_RENDERER_TYPES_SKIPPING_ALL_VALUES,
  defaultJsonFormRegistry,
} from "../lib/default-registry";
import { setByPath } from "../lib/path";

/**
 * Stable, SSR-friendly id slug for a field. Dots are escaped (HTML id can't
 * contain `.` reliably across browsers + CSS queries).
 */
export function fieldIdSlug(formId: string, name: string): string {
  return `${formId}-${name.replace(/\./g, "_")}`;
}

function widthToClass(w: FieldDefinition["width"]): string | undefined {
  if (w == null || w === "full") return undefined;
  if (w === "half" || w === "third" || w === "quarter") return "md:col-span-1";
  return undefined;
}

export interface FieldWrapperProps {
  field: FieldDefinition;
  renderer: FieldRenderer;
  formLabelPosition?: "top" | "left";
  loadingFallback?: ReactNode;
}

/**
 * The single layout shell every field renderer flows through.
 * Owns: label, helper text, error message, ARIA wiring (via `ariaProps`),
 * visibility unmount, disabled merging, RHF Controller binding.
 *
 * v0.1.2 — ARIA is now passed through `FieldRendererArgs.ariaProps` instead
 * of via `Slot.Root` (which silently failed for Popover-wrapped controls and
 * non-form group roots).
 */
export function FieldWrapper({
  field,
  renderer,
  formLabelPosition,
  loadingFallback,
}: FieldWrapperProps) {
  const { control, register, unregister, trigger, getFieldState, getValues } =
    useFormContext();
  const ctx = useJsonFormContext();

  // v0.2.0 (A2) — three-mode subscription gate. The default v0.1.x behavior
  // was a full-bag `useWatch({ control })` on every field, re-rendering the
  // whole form on every keystroke. Now resolved per-field:
  //
  //   • snapshot — built-in default renderer (audited not to read
  //     `allValues`) OR explicit opt-out via `dependsOn: []`. Skip the
  //     watch; `allValues` is a `getValues()` snapshot at render.
  //   • narrow — `dependsOn: ['a','b']`. Subscribe only to those paths;
  //     rebuild a path-keyed bag via `setByPath`.
  //   • fullbag — fallback. Preserves v0.1.x behavior for custom renderers
  //     that didn't opt in.
  //
  // The whitelist check resolves on the FINAL renderer identity (not just
  // `field.type`) so a consumer-registered renderer replacing `text`
  // correctly opts back into full-bag unless it sets `dependsOn`.
  const dependsOn = field.dependsOn;
  const hasDependsOn = Array.isArray(dependsOn);
  const isBuiltinDefault =
    BUILTIN_RENDERER_TYPES_SKIPPING_ALL_VALUES.has(field.type) &&
    renderer === defaultJsonFormRegistry[field.type];
  const subscriptionMode: "snapshot" | "narrow" | "fullbag" =
    isBuiltinDefault || (hasDependsOn && dependsOn.length === 0)
      ? "snapshot"
      : hasDependsOn && dependsOn.length > 0
        ? "narrow"
        : "fullbag";

  // Always call `useWatch` once with mode-conditional inputs to keep hook
  // order stable. `disabled: true` skips the subscription in snapshot mode.
  const watched = useWatch(
    (subscriptionMode === "snapshot"
      ? { control, disabled: true }
      : subscriptionMode === "narrow"
        ? { control, name: dependsOn as ReadonlyArray<string> }
        : { control }) as never,
  );

  let allValues: Record<string, unknown>;
  if (subscriptionMode === "snapshot") {
    allValues = (getValues() ?? {}) as Record<string, unknown>;
  } else if (subscriptionMode === "narrow") {
    const arr = Array.isArray(watched) ? watched : [];
    const bag: Record<string, unknown> = {};
    const names = dependsOn as ReadonlyArray<string>;
    for (let i = 0; i < names.length; i++) {
      setByPath(bag, names[i], arr[i]);
    }
    allValues = bag;
  } else {
    allValues = (watched ?? {}) as Record<string, unknown>;
  }

  const { visible, enabled, required } = useConditional(field);

  // Unmount-clean: when `visibleWhen` flips a field invisible and the consumer
  // hasn't set `keepValueWhenHidden`, drop the registered key so submission
  // strips it (C1 lock).
  useEffect(() => {
    if (field.type === "hidden") return;
    if (!visible && !field.keepValueWhenHidden) {
      unregister(field.name as Path<FieldValues>, { keepDefaultValue: true });
    }
  }, [visible, field.name, field.type, field.keepValueWhenHidden, unregister]);

  // T2.6 — when `requiredWhen` flips a field's required state false→true on
  // a field the user has already touched, trigger validation so the
  // "required" error surfaces immediately instead of waiting for the next
  // blur / submit. The first-render skip prevents pre-interaction errors.
  const prevRequiredRef = useRef(required);
  useEffect(() => {
    if (!field.requiredWhen) return;
    const prev = prevRequiredRef.current;
    prevRequiredRef.current = required;
    if (prev === required) return;
    if (!required) return;
    const state = getFieldState(field.name as Path<FieldValues>);
    if (state.isTouched || state.isDirty) {
      void trigger(field.name as Path<FieldValues>);
    }
  }, [required, field.requiredWhen, field.name, trigger, getFieldState]);

  // `hidden` fields are tracked but render nothing — register imperatively so
  // they always submit.
  useEffect(() => {
    if (field.type !== "hidden") return;
    register(field.name as Path<FieldValues>);
  }, [field.type, field.name, register]);

  if (!visible) return null;
  if (field.type === "hidden") return null;

  const labelPosition = field.labelPosition ?? formLabelPosition ?? "top";
  const controlId = fieldIdSlug(ctx.formId, field.name);
  const labelId = `${controlId}-label`;
  const descriptionId = `${controlId}-description`;
  const errorId = `${controlId}-error`;
  const isDisabled = !enabled || !!field.disabled;
  const isReadOnly = !!field.readOnly;

  const wrapperLayout =
    labelPosition === "left"
      ? "grid grid-cols-[10rem_1fr] items-start gap-x-3 gap-y-1"
      : "flex flex-col gap-1.5";

  return (
    <Controller
      control={control}
      name={field.name as Path<FieldValues>}
      render={({ field: controller, fieldState }) => {
        const errorMessage = fieldState.error?.message
          ? String(fieldState.error.message)
          : undefined;

        const describedBy = buildDescribedBy(
          field.description ? descriptionId : undefined,
          errorMessage ? errorId : undefined,
        );

        const ariaProps: FieldAriaProps = {
          id: controlId,
          labelledBy: labelId,
          "aria-required": required ? true : undefined,
          "aria-invalid": errorMessage ? true : undefined,
          "aria-disabled": isDisabled ? true : undefined,
          "aria-describedby": describedBy,
        };

        const rendered = renderer({
          field,
          value: controller.value,
          onChange: (next: unknown) => controller.onChange(next),
          onBlur: () => controller.onBlur(),
          error: errorMessage,
          disabled: isDisabled,
          readOnly: isReadOnly,
          allValues,
          formApi: ctx,
          ariaProps,
        });

        return (
          <div
            data-jsonform-field={field.name}
            data-jsonform-type={field.type}
            data-disabled={isDisabled ? "true" : undefined}
            className={cn(
              "group/field",
              wrapperLayout,
              widthToClass(field.width),
            )}
          >
            {field.label ? (
              <label
                id={labelId}
                htmlFor={controlId}
                className={cn(
                  "text-sm font-medium text-foreground",
                  labelPosition === "left" ? "pt-1.5" : undefined,
                  isDisabled ? "opacity-60" : undefined,
                )}
              >
                {field.label}
                {required ? (
                  <span aria-hidden="true" className="ml-0.5 text-destructive">
                    {ctx.strings.requiredIndicator}
                  </span>
                ) : null}
              </label>
            ) : null}

            <div
              className={cn(
                "flex flex-col gap-1",
                labelPosition === "left" ? "min-w-0" : undefined,
              )}
            >
              <Suspense
                fallback={
                  loadingFallback ?? (
                    <div className="h-9 w-full animate-pulse rounded-md bg-muted/40" />
                  )
                }
              >
                {rendered}
              </Suspense>

              {field.description ? (
                <p id={descriptionId} className="text-xs text-muted-foreground">
                  {field.description}
                </p>
              ) : null}

              {errorMessage ? (
                <p
                  id={errorId}
                  role="alert"
                  className="text-xs text-destructive"
                >
                  {errorMessage}
                </p>
              ) : null}
            </div>
          </div>
        );
      }}
    />
  );
}

function buildDescribedBy(
  descriptionId: string | undefined,
  errorId: string | undefined,
): string | undefined {
  const ids: string[] = [];
  if (descriptionId) ids.push(descriptionId);
  if (errorId) ids.push(errorId);
  return ids.length ? ids.join(" ") : undefined;
}

"use client";

import { Input } from "@/components/ui/input";
import type { FieldRenderer } from "../types";

const TYPE_TO_INPUT_TYPE: Record<string, string> = {
  text: "text",
  email: "email",
  password: "password",
  url: "url",
  tel: "tel",
  number: "number",
};

export const FieldText: FieldRenderer = ({
  field,
  value,
  onChange,
  onBlur,
  disabled,
  readOnly,
  ariaProps,
}) => {
  const inputType = TYPE_TO_INPUT_TYPE[field.type] ?? "text";
  const isNumberField = field.type === "number";
  return (
    <Input
      id={ariaProps.id}
      type={inputType}
      value={value == null ? "" : String(value)}
      onChange={(e) => {
        const raw = e.target.value;
        // T2.5 — for `number` fields, surface an empty input as `undefined`
        // rather than `""`. `z.coerce.number()` turns `""` into `0`, which
        // produces surprising "value is 0 but the box is empty" UX. With
        // `undefined`, optional fields validate cleanly and required
        // fields surface the right "this field is required" error.
        if (isNumberField && raw === "") {
          onChange(undefined);
          return;
        }
        onChange(raw);
      }}
      onBlur={onBlur}
      placeholder={field.placeholder}
      disabled={disabled}
      readOnly={readOnly}
      autoComplete={field.autoComplete}
      autoFocus={field.autoFocus}
      min={field.min}
      max={field.max}
      step={field.step}
      aria-required={ariaProps["aria-required"]}
      aria-invalid={ariaProps["aria-invalid"]}
      aria-disabled={ariaProps["aria-disabled"]}
      aria-describedby={ariaProps["aria-describedby"]}
    />
  );
};

export default FieldText;

"use client";

import { Textarea } from "@/components/ui/textarea";
import type { FieldRenderer } from "../types";

export const FieldTextarea: FieldRenderer = ({
