        return (
          <div key={String(opt.value)} className="flex items-start gap-2">
            <Checkbox
              id={optId}
              checked={isChecked}
              onCheckedChange={(c) => toggle(opt.value, c === true)}
              disabled={disabled || opt.disabled}
            />
            <div className="flex flex-col">
              <Label htmlFor={optId} className="font-normal">
