import { FieldFallback } from "./field-fallback";

export interface JsonFormFieldProps {
  /** Field name to look up in the active schema. */
  name: string;
  /**
   * Optional override registry for this single field. Falls back to the
   * form-level merged registry (built from `<JsonForm fieldRegistry>`
   * spread over the default registry).
   */
  registry?: Record<string, FieldRenderer>;
}

/**
 * Standalone field renderer for fully-headless layouts. Looks up the field
 * by `name` in the current schema, resolves a renderer from the registry,
 * wraps it in `<FieldWrapper>`. Throws (dev) if the field isn't found.
 *
 * The form-level merged registry is exposed via `ctx.fieldRegistry`.
 */
export function JsonFormField({ name, registry }: JsonFormFieldProps) {
  const ctx = useJsonFormContext();
  const field = useMemo(
    () => ctx.schema.fields.find((f) => f.name === name),
    [ctx.schema.fields, name],
  );

  if (!field) {
    if (process.env.NODE_ENV !== "production") {
      console.warn(
        `[json-form] <JsonFormField name="${name}"> — no field with this name in the current schema.`,
      );
    }
    return null;
  }

  const merged = registry ?? ctx.fieldRegistry;
  const renderer = merged[field.type] ?? FieldFallback;
  return <FieldWrapper field={field} renderer={renderer} />;
}

export default JsonFormField;

"use client";

import { useCallback, useEffect, useMemo, useRef } from "react";
import { useForm, type UseFormReturn } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import type {
  FormSchema,
  JsonFormHandle,
  JsonFormStrings,
  UseJsonFormOptions,
  UseJsonFormReturn,
} from "../types";
import { compileStructural, injectStrings } from "../lib/schema-compiler";
import { mergeStrings } from "../lib/strings";
import { validateSchemaDev } from "../lib/validate-schema";

/**
 * Headless factory hook. Builds the Zod schema, instantiates `useForm`
 * with the resolver, returns everything needed to render the form
 * yourself (or for `<JsonForm>` to render it for you).
 */
export function useJsonForm<TValues extends Record<string, unknown> = Record<string, unknown>>(
  schema: FormSchema,
  options: UseJsonFormOptions<TValues> = {},
): UseJsonFormReturn<TValues> {
  const strings: JsonFormStrings = useMemo(() => mergeStrings(options.strings), [options.strings]);

  // Run dev-only schema sanity checks once per schema identity
  useMemo(() => {
    validateSchemaDev(schema);
  }, [schema]);

  // v0.1.7 (C1) — two-memo compile pipeline. The structural step (field-list
  // extraction + schema reference) caches on schema identity; the strings
  // injection (Zod chain construction + outer refinements) caches on the
  // structural + strings pair. Strings-only changes (locale switch, error
  // template overrides) skip the schema re-walk.
  const structural = useMemo(() => compileStructural(schema), [schema]);
  const zodSchema = useMemo(
    () => injectStrings(structural, strings),
    [structural, strings],
  );

  const defaultValues = useMemo(() => {
    return mergeDefaultValues<TValues>(schema, options.defaultValues);
  }, [schema, options.defaultValues]);

  const form = useForm<TValues>({
    // `zodSchema as never` bypasses zodResolver's overload matching.
    // The resolver has 4 overloads (v3/v4 × raw/non-raw); consumer-side
    // overload-resolution behavior depends on which sub-zod the bundler
    // picks for the resolver's `zod/v4/core` import, and that can vary
    // between producer and consumer trees even with identical pinned
    // versions (path-b smoke 2026-05-13 surfaced this). Casting the
    // argument removes the choice; runtime behavior is identical
    // (resolver dispatches at runtime via instanceof checks).
    resolver: zodResolver(zodSchema as never) as never,
    mode: options.validationMode ?? "onTouched",
    defaultValues: defaultValues as never,
    values: options.values as never,
  });

  const handle = useFormHandle(form);

  return {
    form,
    zodSchema,
    fieldList: schema.fields,
    isValid: form.formState.isValid,
    isSubmitting: form.formState.isSubmitting,
    handle,
  };
}

/**
 * Merge per-field `defaultValue` with form-level `defaultValues`. Form-level
 * wins on conflict (P-09).
 *
 * v0.2.0 (B1): form-level `defaultValues` deep-merges per leaf via
 * `setByPath`/`walkLeaves` instead of shallow per-top-level-key replacement.
 * `{ address: { city: 'X' } }` at form-level no longer drops sibling per-field
 * defaults at `address.country`, `address.zip`, etc.
 */
function mergeDefaultValues<TValues extends Record<string, unknown>>(
  schema: FormSchema,
  formLevel: Partial<TValues> | undefined,
): Partial<TValues> {
  const out: Record<string, unknown> = {};
  for (const field of schema.fields) {
    if (field.defaultValue !== undefined) {
      setByPath(out, field.name.split("."), field.defaultValue);
    }
  }
  if (formLevel) {
    walkLeaves(formLevel as Record<string, unknown>, [], (path, value) => {
      setByPath(out, path, value);
    });
  }
  return out as Partial<TValues>;
}

/** True for `{}` / `Object.create(null)` shapes. Arrays / Dates / class
 * instances return false so they're treated as terminal leaves. */
function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

/** Write `value` at dot-segments `path` into `obj`, lazily creating
 * intermediate plain-object containers when missing or non-object. */
function setByPath(
  obj: Record<string, unknown>,
  path: ReadonlyArray<string>,
  value: unknown,
): void {
  let cur = obj;
  for (let i = 0; i < path.length - 1; i++) {
    const seg = path[i];
    if (!isPlainObject(cur[seg])) {
      cur[seg] = {};
    }
    cur = cur[seg] as Record<string, unknown>;
  }
  cur[path[path.length - 1]] = value;
}

/** Depth-first walk: invokes `fn(path, leafValue)` for every non-plain-object
 * value reachable from `obj`. Empty objects emit no callback. */
function walkLeaves(
  obj: Record<string, unknown>,
  prefix: ReadonlyArray<string>,
  fn: (path: ReadonlyArray<string>, value: unknown) => void,
): void {
  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const nextPath = [...prefix, key];
    if (isPlainObject(value)) {
      walkLeaves(value, nextPath, fn);
    } else {
      fn(nextPath, value);
    }
  }
}

/** Stable imperative-handle factory; methods read fresh RHF state per call. */
function useFormHandle<TValues extends Record<string, unknown>>(
  form: UseFormReturn<TValues>,
): JsonFormHandle<TValues> {
  const formRef = useRef(form);
  useEffect(() => {
    formRef.current = form;
  }, [form]);

  const submit = useCallback(async () => {
    let result: { ok: boolean; values?: TValues; errors?: Record<string, string> } = { ok: false };
    await formRef.current.handleSubmit(
      (values) => {
        result = { ok: true, values: values as TValues };
      },
      (errors) => {
        const flat: Record<string, string> = {};
        for (const [k, v] of Object.entries(errors)) {
          if (v && typeof v === "object" && "message" in v) {
            flat[k] = String((v as { message?: unknown }).message ?? "");
          }
        }
        result = { ok: false, errors: flat };
      },
    )();
    return result;
  }, []);

  const reset = useCallback((values?: Partial<TValues>) => {
    formRef.current.reset(values as never);
  }, []);
  const setValue = useCallback((name: string, value: unknown) => {
    formRef.current.setValue(name as never, value as never);
  }, []);
  const getValue = useCallback((name: string) => {
    return formRef.current.getValues(name as never);
  }, []);
  const getValues = useCallback(() => formRef.current.getValues() as TValues, []);
  const setError = useCallback((name: string, message: string) => {
    formRef.current.setError(name as never, { message });
  }, []);
  const clearErrors = useCallback((name?: string) => {
    formRef.current.clearErrors(name as never);
  }, []);
  const trigger = useCallback((name?: string | string[]) => {
    return formRef.current.trigger(name as never);
  }, []);
  const focus = useCallback((name: string) => {
    formRef.current.setFocus(name as never);
  }, []);
  const isDirty = useCallback(() => formRef.current.formState.isDirty, []);
  const isValid = useCallback(() => formRef.current.formState.isValid, []);
  const isSubmitting = useCallback(() => formRef.current.formState.isSubmitting, []);

  return useMemo<JsonFormHandle<TValues>>(
    () => ({
      submit, reset, setValue, getValue, getValues,
      setError, clearErrors, trigger, focus,
      isDirty, isValid, isSubmitting,
    }),
    [submit, reset, setValue, getValue, getValues, setError, clearErrors, trigger, focus, isDirty, isValid, isSubmitting],
  );
}

"use client";

import { useMemo } from "react";
import { useFormContext, useWatch } from "react-hook-form";
import type { FieldDefinition } from "../types";
import {
  extractConditionOrFnDeps,
  resolveConditionOrFn,
} from "../lib/condition-evaluator";
import { setByPath } from "../lib/path";

export interface ConditionalState {
  visible: boolean;
  enabled: boolean;
  required: boolean;
}

/**
 * Evaluates `visibleWhen` / `enabledWhen` / `requiredWhen` for a single
 * field.
 *
 * v0.1.6 — narrow-deps subscription (T1.2). The union of static deps across
 * all three conditions drives `useWatch({ name })`, so a conditional that
 * only depends on `country` only re-renders when `country` changes — not on
 * every keystroke anywhere in the form. Function-form conditions can't be
 * statically analyzed (`extractConditionOrFnDeps` returns `null`); we fall
 * back to the full-bag subscription for those.
 *
 * v0.1.3 — memoization on the boolean shape (F-R5). The returned object has
 * stable identity when nothing changed.
 */
export function useConditional(field: FieldDefinition): ConditionalState {
  const { control } = useFormContext();

  const watchTarget = useMemo(() => {
    if (!field.visibleWhen && !field.enabledWhen && !field.requiredWhen) {
      return { mode: "none" as const };
    }
    const allDeps = new Set<string>();
    let anyFnForm = false;
    for (const key of ["visibleWhen", "enabledWhen", "requiredWhen"] as const) {
      const c = field[key];
      if (!c) continue;
      const deps = extractConditionOrFnDeps(c);
      if (deps == null) {
        anyFnForm = true;
        break;
      }
      deps.forEach((d) => allDeps.add(d));
    }
    if (anyFnForm) return { mode: "full" as const };
    return { mode: "narrow" as const, names: Array.from(allDeps) };
  }, [field.visibleWhen, field.enabledWhen, field.requiredWhen]);

  // `useWatch` is called UNCONDITIONALLY (hook rules); the `name` arg drives
  // narrow vs full subscription. RHF returns `[]` for `name: []`, which is
  // fine — we never read it in that case. The `as never` cast matches the
  // codebase's existing RHF-overload-disambiguation pattern (see
  // `use-json-form.ts` resolver cast comment for the precedent rationale);
  // here the union of `{ control, name }` vs `{ control }` ambiguates v7.76
  // overload resolution against the new `compute` overload.
  const watched = useWatch(
    (watchTarget.mode === "narrow"
      ? { control, name: watchTarget.names }
      : { control }) as never,
  );

  const values = useMemo<Record<string, unknown>>(() => {
    if (watchTarget.mode === "narrow") {
      // RHF returns an array (positional) when `name` is an array. Rebuild
      // a nested bag via `setByPath` so the condition evaluator's
      // `getByPath('address.city')` walks into the right shape.
      const arr = Array.isArray(watched) ? watched : [];
      const bag: Record<string, unknown> = {};
      watchTarget.names.forEach((n, i) => {
        setByPath(bag, n, arr[i]);
      });
      return bag;
    }
    return (watched ?? {}) as Record<string, unknown>;
  }, [watched, watchTarget]);

  const visible = field.visibleWhen
    ? resolveConditionOrFn(field.visibleWhen, values)
    : true;
  const enabled = field.enabledWhen
    ? resolveConditionOrFn(field.enabledWhen, values)
    : true;
  const required = field.requiredWhen
    ? resolveConditionOrFn(field.requiredWhen, values)
    : false;

  return useMemo<ConditionalState>(
    () => ({ visible, enabled, required }),
    [visible, enabled, required],
  );
}

"use client";

import { useMemo } from "react";
import { useFormContext, useWatch } from "react-hook-form";
import type { FieldDefinition } from "../types";
import { interpolate, parseExpression } from "../lib/expression-parser";
import { setByPath } from "../lib/path";

/**
 * Evaluate a `computed` field's value. Two forms:
 *   - `expression: '{firstName} {lastName}'` — pure interpolation
 *   - `compute: (args) => unknown` — function escape hatch
 *
 * v0.1.6 — narrow-deps subscription (T1.2). For the `expression` form we
 * statically extract the referenced field paths from the parsed template and
 * scope the `useWatch` to those names; the `compute` form is opaque and
 * falls back to a full-bag subscription.
 *
 * v0.1.3 — inline evaluation (F-R5). The body is cheap (string interpolation
 * OR a single function call) and `field-computed.tsx` has an outer
 * value-equality guard before propagating to RHF, so referential instability
 * of the return value is not a correctness concern.
 */
export function useComputed(field: FieldDefinition): unknown {
  const { control } = useFormContext();

  const parsed = useMemo(() => {
    if (!field.expression) return null;
    return parseExpression(field.expression);
  }, [field.expression]);

  // Static deps when we have an `expression`; full-bag fallback for the
  // `compute` function form (or when neither is set — short-circuit later).
  const watchTarget = useMemo(() => {
    if (parsed) {
      return { mode: "narrow" as const, names: Array.from(parsed.deps) };
    }
    return { mode: "full" as const };
  }, [parsed]);

  // `as never` matches the codebase's RHF-overload pattern; v7.76 added a
  // `compute` overload that ambiguates union-arg call sites here.
  const watched = useWatch(
    (watchTarget.mode === "narrow"
      ? { control, name: watchTarget.names }
      : { control }) as never,
  );

  const values = useMemo<Record<string, unknown>>(() => {
    if (watchTarget.mode === "narrow") {
      const arr = Array.isArray(watched) ? watched : [];
      const bag: Record<string, unknown> = {};
      watchTarget.names.forEach((n, i) => {
        setByPath(bag, n, arr[i]);
      });
      return bag;
    }
    return (watched ?? {}) as Record<string, unknown>;
  }, [watched, watchTarget]);

  if (field.expression && parsed) {
    return interpolate(parsed, values);
  }
  if (field.compute) {
    return field.compute({ values });
  }
  return undefined;
}

"use client";

import { useEffect, useMemo, useRef } from "react";

/**
 * Returns a debounced version of `fn` that delays invocation by `delay` ms.
 * Hand-rolled — avoiding `use-debounce` npm dep for ~15 lines of logic.
 */
export function useDebouncedCallback<TArgs extends unknown[]>(
  fn: (...args: TArgs) => void,
  delay: number,
): (...args: TArgs) => void {
  const fnRef = useRef(fn);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Keep the latest fn reference without re-creating the debounced wrapper.
  useEffect(() => {
    fnRef.current = fn;
  }, [fn]);

  // Clear on unmount.
  useEffect(() => {
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  return useMemo(() => {
    return (...args: TArgs) => {
      if (timerRef.current) clearTimeout(timerRef.current);
      if (delay <= 0) {
        fnRef.current(...args);
        return;
      }
      timerRef.current = setTimeout(() => {
        fnRef.current(...args);
      }, delay);
    };
  }, [delay]);
}

"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useFormContext } from "react-hook-form";
import type { FieldDefinition, FieldOption, FieldOptionsResolver } from "../types";

export interface AsyncOptionsState {
  options: FieldOption[];
  loading: boolean;
  error: string | null;
  /** Triggers a re-fetch with the same query (used by the Retry button). */
  retry: () => void;
  /** Update the search query (combobox typing). */
  setQuery: (q: string) => void;
}

const DEFAULT_DEBOUNCE = 200;

/**
 * Manages an async options resolver: debounce, loading state, error+retry.
 * Static options pass through directly (no state — derived on render).
 */
export function useAsyncOptions(field: FieldDefinition): AsyncOptionsState {
  const { getValues } = useFormContext();
  const [asyncOptions, setAsyncOptions] = useState<FieldOption[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [query, setQueryState] = useState("");
  const [tick, setTick] = useState(0);
  const generation = useRef(0);

  const isAsync = typeof field.options === "function";
  const staticOptions = useMemo<FieldOption[]>(
    () => (Array.isArray(field.options) ? (field.options as FieldOption[]) : []),
    [field.options],
  );
  const debounce = field.optionsDebounce ?? DEFAULT_DEBOUNCE;

  useEffect(() => {
    if (!isAsync) return;
    const resolver = field.options as FieldOptionsResolver;
    // Loading + error reset before the network call is intentional —
    // ergonomic "spinner before fetch" UX. Suppress the React Compiler
    // cascading-render lint; the subsequent then/catch are stable.
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setLoading(true);
    setError(null);
    const myGen = ++generation.current;
    const controller = new AbortController();

    const handle = setTimeout(() => {
      resolver({
        query,
        allValues: getValues() as Record<string, unknown>,
        signal: controller.signal,
      })
        .then((next) => {
          if (myGen !== generation.current) return;
          setAsyncOptions(next);
          setLoading(false);
        })
        .catch((err: unknown) => {
          if (myGen !== generation.current) return;
          // AbortError is expected on supersede/unmount — don't surface it.
          if (err instanceof DOMException && err.name === "AbortError") return;
          setAsyncOptions([]);
          setLoading(false);
          setError(err instanceof Error ? err.message : String(err));
        });
    }, debounce);

    return () => {
      clearTimeout(handle);
      controller.abort();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isAsync, query, debounce, tick]);

  const retry = useCallback(() => setTick((t) => t + 1), []);
  const setQuery = useCallback((q: string) => setQueryState(q), []);

  return {
    options: isAsync ? asyncOptions : staticOptions,
    loading: isAsync ? loading : false,
    error: isAsync ? error : null,
    retry,
    setQuery,
  };
}

import { z } from "zod";
import type { ZodObject, ZodTypeAny } from "zod";
import type { FieldDefinition, FieldValidators, FormSchema, JsonFormStrings } from "../types";
import { resolveConditionOrFn } from "./condition-evaluator";
import { formatErrorTemplate } from "./strings";
import { isValueField } from "./validate-schema";
import { getByPath } from "./path";

/**
 * v0.1.7 (C1) — compile pipeline split into two stages for cache granularity:
 *
 *   compileStructural(schema)        → intermediate representation, schema-keyed
 *   injectStrings(structural, strings) → final ZodObject, strings-keyed
 *   compileSchema(schema, strings)   → composition wrapper (internal-only — not
 *                                       exported from index.ts; kept for code
 *                                       readability and any direct internal call)
 *
 * Why the split: in `useJsonForm`, `strings` identity changes (locale switch,
 * error-message overrides) shouldn't re-walk the schema's field list. The
 * two-memo pattern caches the structural step on schema identity, and only
 * the string-injection step runs on strings change. For typical schemas the
 * absolute saving is microseconds, but the cleanly-separated stages make the
 * cache reasoning obvious and free us from RHF re-initialization on
 * strings-only updates (the resolver wraps the new Zod object — RHF detects
 * the resolver identity change but reuses prior form state).
 *
 * Pipeline (per the v0.1.0 plan):
 *   1. Walk value-carrying fields, build a per-field Zod chain from
 *      `field.validators` + base type.
 *   2. Group fields by dot-path roots, build a nested ZodObject via path-trie.
 *   3. Apply `field.validate` (sync) + `field.validateAsync` via per-field
 *      `.superRefine()` (resolver evaluates after structural validators).
 *   4. Apply form-level `schema.validate` via an outer `.superRefine()`.
 *   5. Apply `requiredWhen` via another outer `.superRefine()` that checks
 *      visibility-aware required-ness against the runtime values bag.
 *   6. Merge `schema.zodSchema` LAST — consumer-provided keys overwrite
 *      DSL-generated ones (M-03 / T8 lock).
 *
 * Steps 1 + 2 + 5 + 6 reference `strings` (via `errorTemplates.*` messages
 * baked into the constraint chains); step 1 also runs `buildFieldZod` per
 * field which is the bulk of the per-field work. So `injectStrings` does
 * most of the heavy lifting; `compileStructural` is the cheap "field list
 * collection" memo whose output is reused across strings changes.
 */

/**
 * Schema-keyed intermediate. Internal-only; not exported from index.ts.
 *
 * Holds the value-carrying field list pre-extracted (so `injectStrings`
 * doesn't re-filter on every strings change) plus a reference to the source
 * `FormSchema` for the outer-refinement steps (custom validators / form-level
 * validate / requiredWhen / consumer-zodSchema merge).
 */
export interface CompiledStructural {
  readonly leafFields: ReadonlyArray<FieldDefinition>;
  readonly schema: FormSchema;
}

/** Schema-keyed compile stage. Cheap; safe to re-run on any schema change. */
export function compileStructural(schema: FormSchema): CompiledStructural {
  const leafFields: FieldDefinition[] = [];
  for (const field of schema.fields) {
    if (!isValueField(field)) continue;
    leafFields.push(field);
  }
  return { leafFields, schema };
}

/** Strings-keyed compile stage. Builds the final Zod chains + outer refinements. */
export function injectStrings(
  structural: CompiledStructural,
  strings: JsonFormStrings,
): ZodObject<Record<string, ZodTypeAny>> {
  // 1. Build flat leaf map: 'path' → ZodType (strings baked in)
  const leaves = new Map<string, ZodTypeAny>();
  for (const field of structural.leafFields) {
    leaves.set(field.name, buildFieldZod(field, strings));
  }

  // 2. Nested ZodObject via path-trie
  let zod = buildNestedZodObject(leaves);

  // 3. Per-field custom sync + async validators via outer .superRefine
  zod = applyCustomValidators(zod, structural.schema.fields);

  // 4. Form-level validate
  if (structural.schema.validate) {
    const formValidate = structural.schema.validate;
    zod = zod.superRefine((values, ctx) => {
      const errors = formValidate({ values: values as Record<string, unknown> });
      if (!errors) return;
      for (const [path, message] of Object.entries(errors)) {
        ctx.addIssue({
          code: "custom",
          path: path.split("."),
          message,
        });
      }
    }) as ZodObject<Record<string, ZodTypeAny>>;
  }

  // 5. requiredWhen — conditional required
  zod = applyRequiredWhen(zod, structural.schema.fields, strings);

  // 6. Merge consumer's zodSchema — consumer wins per-key
  if (structural.schema.zodSchema) {
    zod = mergeZodSchemas(zod, structural.schema.zodSchema);
  }

  return zod;
}

/**
 * Composition wrapper. Same signature as v0.1.x for any internal callsite
 * that wants the one-shot compile. Equivalent to
 * `injectStrings(compileStructural(schema), strings)`.
 */
export function compileSchema(
  schema: FormSchema,
  strings: JsonFormStrings,
): ZodObject<Record<string, ZodTypeAny>> {
  return injectStrings(compileStructural(schema), strings);
}

// ─── Per-field base Zod construction ─────────────────────────────────────────

function buildFieldZod(field: FieldDefinition, strings: JsonFormStrings): ZodTypeAny {
  const v = field.validators ?? {};
  let chain: ZodTypeAny;

  switch (field.type) {
    case "text":
    case "email":
    case "password":
    case "url":
    case "tel":
    case "textarea":
    case "code": {
      let s = z.string();
      // built-in format checks derived from type
      if (field.type === "email") {
        s = s.email(extractMessage(v.email, strings.errorTemplates.email));
      }
      if (field.type === "url") {
        s = s.url(extractMessage(v.url, strings.errorTemplates.url));
      }
      // declared validators
      if (v.minLength != null) {
        const { value, message } = normalizeNumeric(v.minLength, strings.errorTemplates.minLength);
        s = s.min(value, formatErrorTemplate(message, { n: value }));
      }
      if (v.maxLength != null) {
        const { value, message } = normalizeNumeric(v.maxLength, strings.errorTemplates.maxLength);
        s = s.max(value, formatErrorTemplate(message, { n: value }));
      }
      if (v.pattern != null) {
        const { value, message } = normalizePattern(v.pattern, strings.errorTemplates.pattern);
        try {
          const re = new RegExp(value);
          s = s.regex(re, message);
        } catch {
          // invalid regex — leave the field non-strictly-validated
        }
      }
      if (v.email && field.type !== "email") {
        s = s.email(extractMessage(v.email, strings.errorTemplates.email));
      }
      if (v.url && field.type !== "url") {
        s = s.url(extractMessage(v.url, strings.errorTemplates.url));
      }
      chain = applyRequired(s, v, strings);
      break;
    }

    case "number":
    case "slider":
    case "rating": {
      // z.coerce.number handles the <input> string→number conversion
      let n = z.coerce.number();
      if (v.min != null) {
        const { value, message } = normalizeNumeric(v.min, strings.errorTemplates.min);
        n = n.gte(Number(value), formatErrorTemplate(message, { n: value }));
      }
      if (v.max != null) {
        const { value, message } = normalizeNumeric(v.max, strings.errorTemplates.max);
        n = n.lte(Number(value), formatErrorTemplate(message, { n: value }));
      }
      chain = applyRequired(n, v, strings);
      break;
    }

    case "checkbox":
    case "switch":
      chain = applyRequiredBoolean(z.boolean(), v, strings);
      break;

    case "select":
    case "radio-group":
      chain = applyRequiredUnknown(z.unknown(), v, strings);
      break;

    case "multi-select":
    case "checkbox-group":
      chain = applyRequiredArray(z.array(z.unknown()), v, strings);
      break;

    case "date":
    case "time":
    case "datetime":
      chain = applyRequired(z.string(), v, strings);
      break;

    case "richtext":
      // Plate `Value` = `Array<TElement | TText>`. Required = at least one
      // node that contains non-empty text (we can't strict-check the inner
      // shape without pulling platejs into the compiler, so a permissive
      // array check + a custom-validate hook covers it).
      chain = applyRequiredRichtext(v, strings);
      break;

    case "date-range":
      chain = applyRequiredUnknown(
        z.object({ start: z.string(), end: z.string() }),
        v,
        strings,
      );
      break;

    case "computed":
    case "hidden":
      // Carry value through; only `required` matters (e.g., CSRF token).
      chain = applyRequiredUnknown(z.unknown(), v, strings);
      break;

    default:
      // unknown/consumer-registered type → permissive default
      chain = applyRequiredUnknown(z.unknown(), v, strings);
  }

  return chain;
}

// ─── Required-handling per base type ─────────────────────────────────────────

function applyRequired(s: ZodTypeAny, v: FieldValidators, strings: JsonFormStrings): ZodTypeAny {
  if (!v.required) {
    if (s instanceof z.ZodString) return s.optional().or(z.literal(""));
    return s.optional();
  }
  const message = typeof v.required === "string" ? v.required : strings.errorTemplates.required;
  if (s instanceof z.ZodString) {
    return (s as z.ZodString).min(1, message);
  }
  // For numbers (incl. ZodCoercedNumber) and other types, the resolver
  // already rejects undefined values when not made optional.
  return s.refine((val) => val !== undefined && val !== null && val !== "", { message });
}

function applyRequiredBoolean(s: z.ZodBoolean, v: FieldValidators, strings: JsonFormStrings): ZodTypeAny {
  if (!v.required) return s.optional();
  const message = typeof v.required === "string" ? v.required : strings.errorTemplates.required;
  return s.refine((val) => val === true, { message });
}

function applyRequiredUnknown<T extends ZodTypeAny>(s: T, v: FieldValidators, strings: JsonFormStrings): ZodTypeAny {
  if (!v.required) return s.optional();
  const message = typeof v.required === "string" ? v.required : strings.errorTemplates.required;
  return s.refine((val) => val !== undefined && val !== null && val !== "", { message });
}

function applyRequiredArray(s: z.ZodArray<ZodTypeAny>, v: FieldValidators, strings: JsonFormStrings): ZodTypeAny {
  if (!v.required) return s.optional();
  const message = typeof v.required === "string" ? v.required : strings.errorTemplates.required;
  return s.min(1, message);
}

function applyRequiredRichtext(v: FieldValidators, strings: JsonFormStrings): ZodTypeAny {
  const base = z.array(z.unknown());
  if (!v.required) return base.optional();
  const message = typeof v.required === "string" ? v.required : strings.errorTemplates.required;
  // Required = non-empty after stripping the "single empty paragraph" default.
  return base.refine((nodes) => richtextHasContent(nodes as unknown[]), { message });
}

function richtextHasContent(nodes: unknown[]): boolean {
  if (!Array.isArray(nodes) || nodes.length === 0) return false;
  // Walk leaf `text` props; consider empty if every text node is whitespace-only.
  function visit(n: unknown): boolean {
    if (n == null || typeof n !== "object") return false;
    const obj = n as Record<string, unknown>;
    if (typeof obj.text === "string") return obj.text.trim().length > 0;
    const children = obj.children;
    if (Array.isArray(children)) return children.some(visit);
    return false;
  }
  return nodes.some(visit);
}

// ─── Validator normalization helpers ─────────────────────────────────────────

type NumericValidator = number | string | { value: number | string; message: string };

function normalizeNumeric(
  raw: NumericValidator,
  defaultMessage: string,
): { value: number; message: string } {
  if (typeof raw === "object") {
    return { value: Number(raw.value), message: raw.message };
  }
  return { value: Number(raw), message: defaultMessage };
}

type PatternValidator = string | { value: string; message: string };

function normalizePattern(raw: PatternValidator, defaultMessage: string): { value: string; message: string } {
  if (typeof raw === "object") return raw;
  return { value: raw, message: defaultMessage };
}

function extractMessage(raw: boolean | { message: string } | undefined, fallback: string): string {
  if (raw && typeof raw === "object") return raw.message;
  return fallback;
}

// ─── Path-trie → nested ZodObject ────────────────────────────────────────────

type TrieNode = Map<string, TrieNode | ZodTypeAny>;

function isTrieNode(v: TrieNode | ZodTypeAny): v is TrieNode {
  return v instanceof Map;
}

function buildNestedZodObject(leaves: Map<string, ZodTypeAny>): ZodObject<Record<string, ZodTypeAny>> {
  const root: TrieNode = new Map();
  for (const [path, ztype] of leaves) {
    const segments = path.split(".");
    let cur: TrieNode = root;
    for (let i = 0; i < segments.length - 1; i++) {
      const seg = segments[i];
      const existing = cur.get(seg);
      if (existing && isTrieNode(existing)) {
        cur = existing;
      } else {
        const next: TrieNode = new Map();
        cur.set(seg, next);
        cur = next;
      }
    }
    cur.set(segments[segments.length - 1], ztype);
  }

  function trieToZod(trie: TrieNode): ZodObject<Record<string, ZodTypeAny>> {
    const shape: Record<string, ZodTypeAny> = {};
    for (const [key, val] of trie) {
      shape[key] = isTrieNode(val) ? trieToZod(val) : val;
    }
    return z.object(shape);
  }

  return trieToZod(root);
}

// ─── Per-field custom validate + validateAsync ───────────────────────────────

function applyCustomValidators(
  zod: ZodObject<Record<string, ZodTypeAny>>,
  fields: ReadonlyArray<FieldDefinition>,
): ZodObject<Record<string, ZodTypeAny>> {
  const withCustom = fields.filter((f) => isValueField(f) && (f.validate || f.validateAsync));
  if (withCustom.length === 0) return zod;

  return zod.superRefine(async (values, ctx) => {
    for (const f of withCustom) {
      const value = getByPath(values, f.name);
      const allValues = values as Record<string, unknown>;

      // Sync first — short-circuit on error
      if (f.validate) {
        const err = f.validate({ value, allValues });
        if (err) {
          ctx.addIssue({
            code: "custom",
            path: f.name.split("."),
            message: err,
          });
          continue;
        }
      }
      // Async runs only if sync passed
      if (f.validateAsync) {
        const err = await f.validateAsync({ value, allValues });
        if (err) {
          ctx.addIssue({
            code: "custom",
            path: f.name.split("."),
            message: err,
          });
        }
      }
    }
  }) as ZodObject<Record<string, ZodTypeAny>>;
}

// ─── requiredWhen — conditional required ─────────────────────────────────────

function applyRequiredWhen(
  zod: ZodObject<Record<string, ZodTypeAny>>,
  fields: ReadonlyArray<FieldDefinition>,
  strings: JsonFormStrings,
): ZodObject<Record<string, ZodTypeAny>> {
  const conditional = fields.filter((f) => isValueField(f) && f.requiredWhen);
  if (conditional.length === 0) return zod;

  return zod.superRefine((values, ctx) => {
    const allValues = values as Record<string, unknown>;
    for (const f of conditional) {
      const required = resolveConditionOrFn(f.requiredWhen!, allValues);
      if (!required) continue;
      const value = getByPath(values, f.name);
      const isEmpty = value === undefined || value === null || value === "" ||
        (Array.isArray(value) && value.length === 0);
      if (isEmpty) {
        const v = f.validators ?? {};
        const message = typeof v.required === "string" ? v.required : strings.errorTemplates.required;
        ctx.addIssue({
          code: "custom",
          path: f.name.split("."),
          message,
        });
      }
    }
  }) as ZodObject<Record<string, ZodTypeAny>>;
}

// ─── Merge consumer-provided ZodSchema (consumer wins per key) ───────────────

function mergeZodSchemas(
  base: ZodObject<Record<string, ZodTypeAny>>,
  override: ZodObject<Record<string, ZodTypeAny>>,
): ZodObject<Record<string, ZodTypeAny>> {
  const baseShape = base.shape;
  const overrideShape = override.shape;
  const merged: Record<string, ZodTypeAny> = { ...baseShape };
  for (const key of Object.keys(overrideShape)) {
    merged[key] = overrideShape[key];
  }
  return z.object(merged);
}

import type { Condition, ConditionOrFn } from "../types";
import { getByPath } from "./path";

/**
 * Evaluate a Condition against a values bag. Returns the boolean result.
 * Unknown shape (defensive — should never happen if types hold) → true
 * (the "always visible / enabled / required" safe default) + a dev warn
 * at the call site.
 */
export function evaluateCondition(
  cond: Condition,
  values: Record<string, unknown>,
): boolean {
  if ("all" in cond) return cond.all.every((c) => evaluateCondition(c, values));
  if ("any" in cond) return cond.any.some((c) => evaluateCondition(c, values));
  if ("not" in cond) return !evaluateCondition(cond.not, values);

  if ("field" in cond) {
    const v = getByPath(values, cond.field);

    if ("equals" in cond) return Object.is(v, cond.equals);
    if ("notEquals" in cond) return !Object.is(v, cond.notEquals);
    if ("in" in cond) return cond.in.includes(v);
    if ("notIn" in cond) return !cond.notIn.includes(v);
    if ("matches" in cond) {
      if (typeof v !== "string") return false;
      try {
        return new RegExp(cond.matches).test(v);
      } catch {
        return false;
      }
    }
    if ("truthy" in cond) return cond.truthy ? !!v : !v;
    if ("greaterThan" in cond) return typeof v === "number" && v > cond.greaterThan;
    if ("lessThan" in cond) return typeof v === "number" && v < cond.lessThan;
  }

  return true;
}

/**
 * Helper: resolve a `Condition` or function form. The fn form receives the
 * full values bag.
 */
export function resolveConditionOrFn(
  cond: ConditionOrFn,
  values: Record<string, unknown>,
): boolean {
  if (typeof cond === "function") return cond({ values });
  return evaluateCondition(cond, values);
}

/**
 * Walk a Condition tree and collect every field path it references.
 * Used to subscribe to only the relevant slice of form state via RHF
 * `watch(deps)` — keeps the per-conditional cost bounded.
 */
export function extractConditionDeps(cond: Condition): Set<string> {
  const deps = new Set<string>();
  function walk(c: Condition): void {
    if ("all" in c) { c.all.forEach(walk); return; }
    if ("any" in c) { c.any.forEach(walk); return; }
    if ("not" in c) { walk(c.not); return; }
    if ("field" in c) { deps.add(c.field); }
  }
  walk(cond);
  return deps;
}

/**
 * For function-form conditions, we can't statically extract deps. Return
 * `null` → caller subscribes to the whole values bag.
 */
export function extractConditionOrFnDeps(cond: ConditionOrFn): Set<string> | null {
  if (typeof cond === "function") return null;
  return extractConditionDeps(cond);
}

import { getByPath } from "./path";

/**
 * Computed-field expression parser. Pure interpolation only:
 *   '{firstName} {lastName}'              → "Hessam Hezaveh"
 *   '{address.city}, {address.country}'   → "Tehran, Iran"
 *
 * NO operators, NO conditionals, NO function calls (per A3 lock). Consumers
 * needing anything more use `compute: (values) => ...` instead.
 */

export interface ParsedExpression {
  /** Ordered parts: alternating literal strings and field references. */
  parts: Array<{ kind: "literal"; text: string } | { kind: "field"; path: string }>;
  /** Set of all field paths referenced. */
  deps: Set<string>;
}

const FIELD_RE = /\{([^{}]+)\}/g;

export function parseExpression(expr: string): ParsedExpression {
  const parts: ParsedExpression["parts"] = [];
  const deps = new Set<string>();
  let lastIndex = 0;
  FIELD_RE.lastIndex = 0;

  let m: RegExpExecArray | null;
  while ((m = FIELD_RE.exec(expr)) !== null) {
    if (m.index > lastIndex) {
      parts.push({ kind: "literal", text: expr.slice(lastIndex, m.index) });
    }
    const path = m[1].trim();
    parts.push({ kind: "field", path });
    deps.add(path);
    lastIndex = m.index + m[0].length;
  }
  if (lastIndex < expr.length) {
    parts.push({ kind: "literal", text: expr.slice(lastIndex) });
  }

  return { parts, deps };
}

/**
 * Render an expression against a values bag. Unknown fields → empty string
 * (plus dev warn from the caller if desired).
 */
export function interpolate(
  parsed: ParsedExpression,
  values: Record<string, unknown>,
): string {
  let out = "";
  for (const part of parsed.parts) {
    if (part.kind === "literal") {
      out += part.text;
    } else {
      const v = getByPath(values, part.path);
      out += v == null ? "" : String(v);
    }
  }
  return out;
}

