export const defaultStrings: JsonFormStrings = {
  submit: "Submit",
  reset: "Reset",
  requiredIndicator: "*",
  optionalIndicator: "(optional)",
  loadingOptions: "Loading…",
  optionsError: "Failed to load options",
  optionsRetry: "Retry",
  noOptions: "No options",
  summaryHeading: "Please fix the following errors:",
  submitFailed: "Submission failed. Please try again.",
  errorTemplates: {
    required: "This field is required",
    minLength: "Must be at least {n} characters",
    maxLength: "Must be at most {n} characters",
    min: "Must be at least {n}",
    max: "Must be at most {n}",
    pattern: "Value does not match the required pattern",
    email: "Must be a valid email address",
    url: "Must be a valid URL",
  },
};

/** Substitute `{n}`, `{value}`, etc. in a template. */
export function formatErrorTemplate(
  template: string,
  params: Record<string, string | number>,
): string {
  return template.replace(/\{(\w+)\}/g, (_, key) =>
    key in params ? String(params[key]) : `{${key}}`,
  );
}

/** Shallow-merge consumer overrides into the default strings dictionary. */
export function mergeStrings(
  overrides: Partial<JsonFormStrings> | undefined,
): JsonFormStrings {
  if (!overrides) return defaultStrings;
  return {
    ...defaultStrings,
    ...overrides,
    errorTemplates: {
      ...defaultStrings.errorTemplates,
      ...(overrides.errorTemplates ?? {}),
    },
  };
}

/**
 * Dot-path helpers used by the expression interpolator + nested ZodObject
 * construction. RHF handles deep-set/get internally for `register('a.b.c')`,
 * but we need read-side dot-path access for `expression: '{address.city}'`.
 */

export function getByPath(obj: unknown, path: string): unknown {
  if (obj == null) return undefined;
  const segments = path.split(".");
  let cur: unknown = obj;
  for (const seg of segments) {
    if (cur == null || typeof cur !== "object") return undefined;
    cur = (cur as Record<string, unknown>)[seg];
  }
  return cur;
}

export function setByPath(obj: Record<string, unknown>, path: string, value: unknown): void {
  const segments = path.split(".");
  const last = segments.pop();
  if (!last) return;
  let cur: Record<string, unknown> = obj;
  for (const seg of segments) {
    if (!(seg in cur) || typeof cur[seg] !== "object" || cur[seg] === null) {
      cur[seg] = {};
    }
    cur = cur[seg] as Record<string, unknown>;
  }
  cur[last] = value;
}

/**
 * Shared error-flattener for RHF's nested error tree.
 *
 * The error tree can be either:
 *   { fieldName: { message: '...', type: '...' } }
 * or deeper:
 *   { address: { city: { message: '...' } } }
 *
 * Both flatten to dot-path keys. Two shapes are exposed because callers want
 * different output: `flattenRhfErrorsToRecord` for callback payloads (record),
 * `flattenRhfErrorsToList` for the summary UI (ordered list).
 */

interface FlatEntry {
  path: string;
  message: string;
}

function* walkRhfErrors(
  errors: Record<string, unknown>,
  prefix = "",
): Generator<FlatEntry> {
  for (const [key, val] of Object.entries(errors)) {
    if (!val) continue;
    const path = prefix ? `${prefix}.${key}` : key;
    if (
      typeof val === "object" &&
      val !== null &&
      "message" in val &&
      typeof (val as { message?: unknown }).message === "string"
    ) {
      yield { path, message: String((val as { message?: unknown }).message) };
      continue;
    }
    if (typeof val === "object" && val !== null) {
      yield* walkRhfErrors(val as Record<string, unknown>, path);
    }
  }
}

/** Flatten errors to `{ 'path.to.field': 'message' }`. Callback-payload shape. */
export function flattenRhfErrorsToRecord(
  errors: Record<string, unknown>,
): Record<string, string> {
  const out: Record<string, string> = {};
  for (const { path, message } of walkRhfErrors(errors)) {
    out[path] = message;
  }
  return out;
}

/** Flatten errors to an ordered list. Summary-UI shape. */
export function flattenRhfErrorsToList(
  errors: Record<string, unknown>,
): Array<{ name: string; message: string }> {
  const out: Array<{ name: string; message: string }> = [];
  for (const { path, message } of walkRhfErrors(errors)) {
    out.push({ name: path, message });
  }
  return out;
}

import type { ReactNode } from "react";
import type {
  FieldDefinition,
  FieldRenderer,
  FieldRendererArgs,
} from "../types";

/**
 * v0.1.7 — narrowed argument shape passed to the typed factory's `impl`
 * callback. Inherits all `FieldRendererArgs` keys except `value` (narrowed
 * to `TValue`) and `field` (narrowed so `field.config[k]` reads as `TConfig`).
 *
 * Internal. The factory unwraps it back to a plain `FieldRenderer` for
 * registry storage — registry consumers see the standard `FieldRendererArgs`
 * shape.
 */
export interface NarrowedRendererArgs<TValue, TConfig>
  extends Omit<FieldRendererArgs, "value" | "field"> {
  value: TValue;
  field: FieldDefinition & {
    config?: { [key: string]: TConfig };
  };
}

export interface DefineFieldRendererConfig<TValue, TConfig> {
  /**
   * Display name surfaced in `<JsonFormDevtools>` and dev-tools panels.
   * Defaults to `"AnonymousRenderer"` when omitted. Attached as a
   * non-enumerable `displayName` property on the returned `FieldRenderer`
   * so registry-walker code can pick it up.
   */
  displayName?: string;
  /**
   * The renderer body. Receives the narrowed args; returns the rendered
   * React node.
   */
  impl: (args: NarrowedRendererArgs<TValue, TConfig>) => ReactNode;
}

/**
 * v0.1.7 — typed factory for custom field renderers.
 *
 * Returns a plain `FieldRenderer` (the same shape consumers use today via
 * `Record<string, FieldRenderer>`) — so the result drops directly into a
 * registry without any other plumbing. The factory is **type-narrowing
 * only**: there's no runtime narrowing of `value` or `field.config`,
 * because RHF values aren't statically known. The generics are
 * consumer-asserted convenience.
 *
 * @example
 * ```tsx
 * import { defineFieldRenderer } from "@ilinxa/json-form";
 *
 * interface ColorConfig {
 *   palette?: string[];
 * }
 *
 * const ColorSwatch = defineFieldRenderer<string, ColorConfig>({
 *   displayName: "ColorSwatch",
 *   impl: ({ value, onChange, field, disabled }) => {
 *     const palette = field.config?.color?.palette ?? ["#FF595E", "#FFCA3A"];
 *     return palette.map((c) => (
 *       <button key={c} onClick={() => onChange(c)} disabled={disabled}>
 *         {value === c ? "✓" : ""}
 *       </button>
 *     ));
 *   },
 * });
 *
 * const registry = { ...defaultJsonFormRegistry, color: ColorSwatch };
 * ```
 */
export function defineFieldRenderer<TValue = unknown, TConfig = unknown>(
  config: DefineFieldRendererConfig<TValue, TConfig>,
): FieldRenderer {
  const renderer: FieldRenderer = (args) =>
    config.impl(args as unknown as NarrowedRendererArgs<TValue, TConfig>);

  // Attach displayName as a non-enumerable property so registry-walker code
  // (e.g., `<JsonFormDevtools>`) can read it without it leaking into
  // `Object.keys` / JSON.stringify of registry maps.
  Object.defineProperty(renderer, "displayName", {
    value: config.displayName ?? "AnonymousRenderer",
    enumerable: false,
    writable: false,
    configurable: false,
  });

  return renderer;
}

"use client";

import { useMemo } from "react";
import { useWatch } from "react-hook-form";
import { useJsonFormContext } from "../json-form-context";
import { setByPath } from "../lib/path";

/**
 * v0.1.7 — narrow-deps single-field watch. Pure ergonomic wrapper around
 * RHF's `useWatch({ control, name })` scoped to one path, resolved against
 * the active `<JsonFormProvider>` context.
 *
 * **Typing caveat:** the generic `<T>` is consumer-asserted. RHF values
 * aren't statically known — the runtime returns whatever the form currently
 * holds at `name`. Treat the generic as a typed-assertion convenience, not a
 * runtime guarantee.
 *
 * Use this hook to build fully-custom form layouts that subscribe to one
 * field's value without re-rendering on every other field's change. Mirrors
 * the narrow-deps pattern shipped in `useConditional` + `useComputed`
 * (v0.1.6) and exposes it to consumer code.
 *
 * @example
 * ```tsx
 * const country = useJsonFormFieldValue<string>("country");
 * return <p>You selected {country}</p>;
 * ```
 */
export function useJsonFormFieldValue<T = unknown>(name: string): T {
  const ctx = useJsonFormContext();
  // `as never` matches the codebase's RHF-overload-disambiguation pattern
  // (see `use-conditional.ts` for the precedent rationale). The v7.76
  // `compute` overload ambiguates single-string-name calls when the
  // resolved Control's value type is unknown.
  return useWatch({ control: ctx.rhf.control, name } as never) as T;
}

/**
 * v0.1.7 — narrow-deps multi-field watch. Returns a path-keyed bag with
 * only the named fields rehydrated via `setByPath` — so consumers can read
 * `bag["address.city"]` via `getByPath` or destructure nested paths
 * naturally.
 *
 * **Typing caveat:** same as `useJsonFormFieldValue<T>` — the generic is
 * consumer-asserted. The returned shape is structurally a `Record<string,
 * unknown>` enriched with whatever `setByPath` walks produce.
 *
 * @example
 * ```tsx
 * const { firstName, lastName } = useJsonFormFieldsValue<{
 *   firstName: string;
 *   lastName: string;
 * }>(["firstName", "lastName"]);
 * ```
 */
export function useJsonFormFieldsValue<
  T extends Record<string, unknown> = Record<string, unknown>,
>(names: ReadonlyArray<string>): T {
  const ctx = useJsonFormContext();
  // `as never` per the same overload-disambiguation rationale above.
  const watched = useWatch({ control: ctx.rhf.control, name: names } as never);

  return useMemo<T>(() => {
    const arr = Array.isArray(watched) ? watched : [];
    const bag: Record<string, unknown> = {};
    names.forEach((n, i) => {
      setByPath(bag, n, arr[i]);
    });
    return bag as T;
  }, [watched, names]);
}

"use client";

import { Suspense, lazy } from "react";

/**
 * v0.1.7 — JsonFormDevtools loader stub. The ~250 LOC panel body lives in
 * `./json-form-devtools-body.tsx` and is fetched via `React.lazy()` only
 * when the component actually renders. In prod (or when the consumer-side
 * import is itself wrapped behind `process.env.NODE_ENV !== "production"`),
 * the body chunk is never fetched.
 *
 * **This is NOT a bundler tree-shake** — the loader stub itself still
 * ships in prod chunks unless the consumer-side import is conditional. For
 * true chunk-level elimination, wrap the usage:
 *
 * ```tsx
 * {process.env.NODE_ENV !== "production" && <JsonFormDevtools />}
 * ```
 *
 * Override the auto-disable via the `force` prop for prod-debug builds.
 */

const LazyBody = lazy(() => import("./json-form-devtools-body"));

export interface JsonFormDevtoolsProps {
  /**
   * Render inline (as a block child) instead of as a floating panel
   * anchored to the bottom-right viewport corner. Inline mode is always
   * visible; floating mode shows a pill-shaped toggle until opened.
   */
  inline?: boolean;
  /**
   * Force-enable in production builds. By default the component returns
   * `null` (no-op) when `process.env.NODE_ENV === "production"`.
   */
  force?: boolean;
  /**
   * Keyboard shortcut to toggle the floating panel open/closed. Ignored in
   * inline mode. Format: `"Ctrl+Shift+J"` (case-insensitive modifiers).
   * Default: `"Ctrl+Shift+J"`.
   */
  shortcut?: string;
  className?: string;
}

export function JsonFormDevtools({
  inline = false,
  force = false,
  shortcut = "Ctrl+Shift+J",
  className,
}: JsonFormDevtoolsProps) {
  if (process.env.NODE_ENV === "production" && !force) return null;

  return (
    <Suspense fallback={null}>
      <LazyBody inline={inline} shortcut={shortcut} className={className} />
    </Suspense>
  );
}

export default JsonFormDevtools;

