/**
 * v0.1.7 — body of the JsonFormDevtools panel. Lives in its own module so
 * the parent `<JsonFormDevtools>` can lazy-load it via `React.lazy()` — the
 * ~250 LOC body chunk only loads when the panel actually renders, while the
 * tiny loader stub ships in the parent module.
 *
 * This module is rendered exclusively from the dynamic-import boundary and
 * is NOT exported from `index.ts`. Consumers reach it only via
 * `<JsonFormDevtools>`.
 */

export interface JsonFormDevtoolsBodyProps {
  inline: boolean;
  shortcut: string;
  className?: string;
}

type Tab = "schema" | "values" | "conditionals" | "errors";

export default function JsonFormDevtoolsBody({
  inline,
  shortcut,
  className,
}: JsonFormDevtoolsBodyProps) {
  const maybeCtx = useJsonFormContextOptional();
  const [open, setOpen] = useState(inline);
  const [tab, setTab] = useState<Tab>("schema");

  // Keyboard shortcut listener (skipped in inline mode — the panel is
  // always rendered then).
  useEffect(() => {
    if (inline) return;
    const handler = (e: KeyboardEvent) => {
      if (matchesShortcut(e, shortcut)) {
        e.preventDefault();
        setOpen((o) => !o);
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [inline, shortcut]);

  const wrapperClass = inline
    ? cn(
        "rounded-lg border border-border bg-card text-card-foreground shadow-sm",
        className,
      )
    : cn(
        "fixed bottom-4 right-4 z-9999 flex w-96 max-w-[calc(100vw-2rem)] flex-col rounded-lg border border-border bg-card text-card-foreground shadow-xl",
        className,
      );

  if (!inline && !open) {
    return (
      <button
        type="button"
        onClick={() => setOpen(true)}
        className="fixed bottom-4 right-4 z-9999 flex h-10 items-center gap-2 rounded-full border border-border bg-card px-4 text-xs font-medium text-foreground shadow-md hover:bg-muted"
        aria-label="Open JsonForm devtools panel"
      >
        <span className="size-2 rounded-full bg-primary" />
        json-form devtools
      </button>
    );
  }

  // v0.2.1 (F-06) — soft-warning fallback when no <JsonFormProvider> is in
  // the tree. Renders an explanatory panel instead of throwing, so the
  // consumer mistake is visible-but-recoverable rather than a hard crash.
  if (!maybeCtx) {
    return (
      <div className={wrapperClass} data-jsonform-devtools data-state="no-provider">
        {!inline ? (
          <header className="flex items-center justify-between border-b border-border px-3 py-2">
            <span className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
              json-form devtools
            </span>
            <button
              type="button"
              onClick={() => setOpen(false)}
              aria-label="Close devtools panel"
              className="rounded p-1 hover:bg-muted"
            >
              <XIcon className="size-3.5" />
            </button>
          </header>
        ) : null}
        <div className="p-3 text-xs text-muted-foreground">
          <p className="mb-1 font-medium text-foreground">No JsonForm context found.</p>
          <p>
            Place <code className="rounded bg-muted px-1">&lt;JsonFormDevtools /&gt;</code>{" "}
            inside a <code className="rounded bg-muted px-1">&lt;JsonForm&gt;</code> or{" "}
            <code className="rounded bg-muted px-1">&lt;JsonFormProvider&gt;</code>{" "}
            tree so the panel can read schema, values, conditionals, and errors.
          </p>
        </div>
      </div>
    );
  }

  const ctx = maybeCtx;

  return (
    <div className={wrapperClass} data-jsonform-devtools>
      {!inline ? (
        <header className="flex items-center justify-between border-b border-border px-3 py-2">
          <span className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
            json-form devtools
          </span>
          <div className="flex items-center gap-1">
            <span className="hidden text-[10px] text-muted-foreground/70 sm:inline">
              {shortcut}
            </span>
            <button
              type="button"
              onClick={() => setOpen(false)}
              aria-label="Close devtools panel"
              className="rounded p-1 hover:bg-muted"
            >
              <XIcon className="size-3.5" />
            </button>
          </div>
        </header>
      ) : null}

      <nav className="flex items-center gap-1 border-b border-border px-2 py-1 text-xs">
        {(["schema", "values", "conditionals", "errors"] as const).map((t) => (
          <button
            key={t}
            type="button"
            onClick={() => setTab(t)}
            className={cn(
              "rounded px-2 py-0.5 transition-colors",
              tab === t
                ? "bg-primary text-primary-foreground"
                : "text-muted-foreground hover:bg-muted",
            )}
          >
            {t}
          </button>
        ))}
      </nav>

      <div className="max-h-100 min-h-40 flex-1 overflow-y-auto p-3 text-xs">
        {tab === "schema" ? <SchemaTab /> : null}
        {tab === "values" ? <ValuesTab /> : null}
        {tab === "conditionals" ? <ConditionalsTab /> : null}
        {tab === "errors" ? <ErrorsTab /> : null}
      </div>

      <footer className="flex items-center justify-between border-t border-border px-3 py-1.5 text-[10px] text-muted-foreground">
        <span data-jsonform-devtools-form-id>{ctx.formId}</span>
        <span>v0.2.1</span>
      </footer>
    </div>
  );
}

// ─── Tabs ────────────────────────────────────────────────────────────────────

function SchemaTab() {
  const ctx = useJsonFormContext();
  const [collapsed, setCollapsed] = useState(false);

  return (
    <div className="flex flex-col gap-2">
      <button
        type="button"
        onClick={() => setCollapsed((c) => !c)}
        className="flex items-center gap-1 text-[10px] font-medium uppercase tracking-wide text-muted-foreground hover:text-foreground"
      >
        {collapsed ? (
          <ChevronRightIcon className="size-3" />
        ) : (
          <ChevronDownIcon className="size-3" />
        )}
        FormSchema ({ctx.schema.fields.length} fields)
      </button>
      {!collapsed ? (
        <pre className="overflow-x-auto rounded-md border border-border bg-muted/30 p-2 font-mono text-[11px] leading-relaxed text-foreground">
          {JSON.stringify(ctx.schema, prettyReplacer, 2)}
        </pre>
      ) : null}
    </div>
  );
}

function ValuesTab() {
  const ctx = useJsonFormContext();
  // Devtools-only subscription — paying the full-bag watch cost is OK here
  // because devtools panels are excluded from normal render paths.
  const values = useWatch({ control: ctx.rhf.control }) ?? {};

  return (
    <pre className="overflow-x-auto rounded-md border border-border bg-muted/30 p-2 font-mono text-[11px] leading-relaxed text-foreground">
      {JSON.stringify(values, prettyReplacer, 2)}
    </pre>
  );
}

function ConditionalsTab() {
  const ctx = useJsonFormContext();

  const conditionalFields = useMemo(
    () =>
      ctx.schema.fields.filter(
        (f) =>
          isValueField(f) && (f.visibleWhen || f.enabledWhen || f.requiredWhen),
      ),
    [ctx.schema.fields],
  );

  if (conditionalFields.length === 0) {
    return (
      <p className="italic text-muted-foreground">
        No conditional fields in this schema.
      </p>
    );
  }

  return (
    <table className="w-full border-collapse text-[11px]">
      <thead>
        <tr className="text-left text-muted-foreground">
          <th className="py-1 pr-2 font-medium">Field</th>
          <th className="py-1 pr-2 font-medium">visible</th>
          <th className="py-1 pr-2 font-medium">enabled</th>
          <th className="py-1 pr-2 font-medium">required</th>
        </tr>
      </thead>
      <tbody className="divide-y divide-border">
        {conditionalFields.map((f) => (
          <ConditionalRow key={f.name} field={f} />
        ))}
      </tbody>
    </table>
  );
}

function ConditionalRow({ field }: { field: FieldDefinition }) {
  // useConditional handles the narrow-deps subscription internally; the
  // devtools row re-renders only when this field's evaluated state flips.
  const { visible, enabled, required } = useConditional(field);

  return (
    <tr>
      <td className="py-1 pr-2 font-mono text-foreground">{field.name}</td>
      <td className="py-1 pr-2">{visible ? "✓" : "✗"}</td>
      <td className="py-1 pr-2">{enabled ? "✓" : "✗"}</td>
      <td className="py-1 pr-2">{required ? "✓" : "✗"}</td>
    </tr>
  );
}

function ErrorsTab() {
  const ctx = useJsonFormContext();
  const { errors } = useFormState({ control: ctx.rhf.control });
  const flat = flattenRhfErrorsToList(errors as Record<string, unknown>);

  if (flat.length === 0) {
    return (
      <p className="italic text-muted-foreground">No errors. Form is valid.</p>
    );
  }

  return (
    <ul className="flex flex-col gap-1">
      {flat.map(({ name, message }) => (
        <li
          key={name}
          className="flex items-baseline gap-2 rounded border border-destructive/30 bg-destructive/5 p-1.5"
        >
          <span className="font-mono text-foreground">{name}</span>
          <span className="text-destructive">{message}</span>
        </li>
      ))}
    </ul>
  );
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

/**
 * JSON.stringify replacer that turns function values into a placeholder
 * (raw schemas often hold validate / compute / visibleWhen callbacks). Also
 * serializes Map / Set / BigInt — `JSON.stringify` itself throws on bigint
 * (v0.2.1 F-08), so the panel would crash if a consumer's form held a
 * bigint value.
 */
function prettyReplacer(_key: string, value: unknown): unknown {
  if (typeof value === "function") return "[Function]";
  if (typeof value === "bigint") return `${value.toString()}n`;
  if (value instanceof Map) return Object.fromEntries(value);
  if (value instanceof Set) return Array.from(value);
  return value;
}

/**
 * Matches a KeyboardEvent against a shortcut string like "Ctrl+Shift+J".
 * Modifiers are case-insensitive; the final key compares against
 * `event.key` (case-insensitive too).
 */
function matchesShortcut(e: KeyboardEvent, shortcut: string): boolean {
  const parts = shortcut.split("+").map((p) => p.trim().toLowerCase());
  const target = parts.pop();
  if (!target) return false;
  if (parts.includes("ctrl") !== e.ctrlKey) return false;
  if (parts.includes("shift") !== e.shiftKey) return false;
  if (parts.includes("alt") !== e.altKey) return false;
  if (parts.includes("meta") !== e.metaKey) return false;
  return e.key.toLowerCase() === target;
}

import type { FieldDefinition, FormSchema } from "../types";
import { extractConditionOrFnDeps } from "./condition-evaluator";

/**
 * Dev-only sanity checks. Emits warnings via `console.warn`. Does NOT throw —
 * a broken schema should still render something (the offending field falls
 * back to "always visible / enabled / always-true" defaults).
 *
 * Skipped in production builds (no-op).
 */
export function validateSchemaDev(schema: FormSchema): void {
  if (process.env.NODE_ENV === "production") return;

  // (1) Duplicate field names
  const seen = new Set<string>();
  for (const field of schema.fields) {
    if (seen.has(field.name)) {
      console.warn(
        `[json-form] Duplicate field name "${field.name}". First occurrence renders; others are ignored.`,
      );
    }
    seen.add(field.name);
  }

  // (2) Value-carrying types without a name (shouldn't be possible per TS,
  //     but defensive in case consumers pass loose JSON)
  for (const field of schema.fields) {
    if (!field.name) {
      console.warn(
        `[json-form] Field of type "${field.type}" has no name. All field types require a stable name.`,
      );
    }
  }

  // (3) Active-conditional count — perf ceiling (O1 lock; threshold bumped
  // from 50 → 200 in v0.2.0 since per-keystroke render count no longer scales
  // with conditional count under the default-registry watch drop).
  let conditionalCount = 0;
  for (const field of schema.fields) {
    if (field.visibleWhen) conditionalCount++;
    if (field.enabledWhen) conditionalCount++;
    if (field.requiredWhen) conditionalCount++;
  }
  if (conditionalCount > 200) {
    console.warn(
      `[json-form] Schema has ${conditionalCount} active conditionals (visibleWhen / enabledWhen / requiredWhen). ` +
        `Performance may degrade past ~200; consider hoisting conditionals into a derived schema or splitting the form.`,
    );
  }

  // (4) Conditional dependency cycles — A.visibleWhen depends on B, B.visibleWhen depends on A, etc.
  const depGraph = new Map<string, Set<string>>();
  for (const field of schema.fields) {
    const deps = new Set<string>();
    for (const key of ["visibleWhen", "enabledWhen", "requiredWhen"] as const) {
      const c = field[key];
      if (!c) continue;
      const fieldDeps = extractConditionOrFnDeps(c);
      if (fieldDeps) fieldDeps.forEach((d) => deps.add(d));
    }
    if (deps.size) depGraph.set(field.name, deps);
  }

  function hasCycle(start: string, visited: Set<string>, stack: Set<string>): string[] | null {
    if (stack.has(start)) return [start];
    if (visited.has(start)) return null;
    visited.add(start);
    stack.add(start);
    const deps = depGraph.get(start);
    if (deps) {
      for (const d of deps) {
        const result = hasCycle(d, visited, stack);
        if (result) return [start, ...result];
      }
    }
    stack.delete(start);
    return null;
  }

  const cycleVisited = new Set<string>();
  for (const name of depGraph.keys()) {
    if (cycleVisited.has(name)) continue;
    const cycle = hasCycle(name, cycleVisited, new Set<string>());
    if (cycle) {
      console.warn(
        `[json-form] Conditional dependency cycle detected: ${cycle.join(" → ")}. ` +
          `Falling back to "always true" for the cyclic fields.`,
      );
      break; // one warn is enough; consumer can fix and re-run
    }
  }

  // (5) v0.1.7 — dangling `dependsOn` references. Match is dot-path-as-flat
  // -string against `schema.fields[i].name` exactly. Fields declared via
  // nested `defaultValue` shapes (e.g., `{ name: 'address', defaultValue:
  // { city: '…' } }`) WON'T satisfy this lint for `'address.city'` —
  // consumers using nested-default patterns need individual leaf entries
  // to declare them lint-visible. Runtime watch-gating that honors
  // `dependsOn` ships in v0.2.0; the lint runs in v0.1.7 so consumers can
  // author forward-compatible schemas now.
  const knownNames = new Set(schema.fields.map((f) => f.name));
  for (const field of schema.fields) {
    if (!field.dependsOn) continue;
    for (const dep of field.dependsOn) {
      if (knownNames.has(dep)) continue;
      console.warn(
        `[json-form] Field "${field.name}" declares dependsOn: "${dep}", ` +
          `but no field with that exact name exists in the schema. ` +
          `Lint matches against schema.fields[].name as a flat dot-path string.`,
      );
    }
  }
}

/** Convenience: skip `section` / `divider` types when walking value-carrying fields. */
export function isValueField(field: FieldDefinition): boolean {
  return field.type !== "section" && field.type !== "divider";
}
